// DASHBOARD
// ─────────────────────────────────────────────
function Dashboard({store,activeSupplier,activeDepot,currentUser}){
  const {entries,returns,inventories,invoices,products,stock,depots,suppliers}=store;
  const supProds=activeSupplier ? products.filter(p=>p.supplierId===activeSupplier.id) : products;
  const totalStock=supProds.reduce((a,p)=>a+(stock[p.id]||0),0);
  const month=new Date().getMonth(), year=new Date().getFullYear();
  const mEntries=entries.filter(e=>new Date(e.date).getMonth()===month&&new Date(e.date).getFullYear()===year&&(!activeSupplier||e.supplierId===activeSupplier.id));
  const mReturns=returns.filter(r=>new Date(r.date).getMonth()===month&&new Date(r.date).getFullYear()===year&&(!activeSupplier||r.supplierId===activeSupplier.id));
  const lowStock=supProds.filter(p=>(stock[p.id]||0)<30);
  const isAdmin = currentUser?.role==="admin";

  // ── État pour l'éditeur de slides ──
  const [showSlideEditor, setShowSlideEditor] = useState(false);
  const [slides, setSlides] = useState(loadSlides);
  const [editSlide, setEditSlide] = useState(null); // {index, emoji, title, sub, bg, accent}
  const ACCENT_COLORS = ["#38bdf8","#4ade80","#fb923c","#a78bfa","#f9a8d4","#fbbf24","#34d399","#f87171"];
  const BG_GRADIENTS = [
    "linear-gradient(135deg,#0c4a6e 0%,#0f172a 100%)",
    "linear-gradient(135deg,#312e81 0%,#1e1b4b 100%)",
    "linear-gradient(135deg,#064e3b 0%,#022c22 100%)",
    "linear-gradient(135deg,#78350f 0%,#431407 100%)",
    "linear-gradient(135deg,#4c0519 0%,#1e0010 100%)",
    "linear-gradient(135deg,#1e3a5f 0%,#0f172a 100%)",
    "linear-gradient(135deg,#1a1a2e 0%,#16213e 100%)",
    "linear-gradient(135deg,#2d1b69 0%,#11998e 100%)",
  ];

  const [uploadingPhoto, setUploadingPhoto] = useState(false);

  const handlePhotoUpload = async (file) => {
    if (!file) return;
    setUploadingPhoto(true);
    try {
      const path = `carousel/${Date.now()}_${file.name.replace(/[^a-z0-9.]/gi,"_")}`;
      const sRef = storageRef(storage, path);
      await uploadBytes(sRef, file);
      const url = await getDownloadURL(sRef);
      setEditSlide(v => ({...v, imageUrl: url, storagePath: path}));
    } catch(e) {
      alert("Erreur upload : " + e.message);
    } finally {
      setUploadingPhoto(false);
    }
  };

  const handleDeletePhoto = async () => {
    if (!editSlide?.storagePath) { setEditSlide(v=>({...v,imageUrl:"",storagePath:""})); return; }
    try {
      await deleteObject(storageRef(storage, editSlide.storagePath));
      setEditSlide(v => ({...v, imageUrl:"", storagePath:""}));
    } catch(e) { setEditSlide(v=>({...v,imageUrl:"",storagePath:""})); }
  };
  const saveAndDispatch = (newSlides) => {
    saveSlides(newSlides);
    setSlides(newSlides);
    window.dispatchEvent(new Event("pharma_slides_updated"));
  };

  const handleSaveSlide = () => {
    if(!editSlide) return;
    const updated = slides.map((s,i)=> i===editSlide.index ? {
      bg:          editSlide.bg,
      emoji:       editSlide.imageUrl ? "" : editSlide.emoji,
      title:       editSlide.title,
      sub:         editSlide.sub,
      accent:      editSlide.accent,
      imageUrl:    editSlide.imageUrl    || "",
      storagePath: editSlide.storagePath || "",
    } : s);
    saveAndDispatch(updated);
    setEditSlide(null);
  };

  const handleAddSlide = () => {
    const newSlide = {bg:BG_GRADIENTS[0],emoji:"✨",title:"Nouveau slide",sub:"Description du slide",accent:"#38bdf8"};
    const updated = [...slides, newSlide];
    saveAndDispatch(updated);
    setEditSlide({index:updated.length-1, ...newSlide});
  };

  const handleDeleteSlide = (idx) => {
    if(slides.length<=1) return;
    const updated = slides.filter((_,i)=>i!==idx);
    saveAndDispatch(updated);
    setEditSlide(null);
  };

  const handleResetSlides = () => {
    saveAndDispatch(DEFAULT_CAROUSEL_SLIDES);
    setEditSlide(null);
  };

  const kpis=[
    {label:"Stock Total",value:totalStock.toLocaleString(),icon:"📦",color:"#38bdf8"},
    {label:"Entrées ce mois",value:mEntries.length,icon:"📥",color:"#4ade80"},
    {label:"Retours ce mois",value:mReturns.length,icon:"↩️",color:"#fb923c"},
    {label:"Inventaires",value:inventories.filter(i=>!activeSupplier||i.supplierId===activeSupplier?.id).length,icon:"🗂️",color:"#a78bfa"},
  ];

  return(
    <div style={{padding:0}}>
      <PageHeader pageId="dashboard" title="📊 Tableau de bord"
        subtitle={monthLabel() + " · " + (activeSupplier ? activeSupplier.name : "Tous fournisseurs")}/>
      <div style={{padding:16}}>
        <ImageCarousel/>

        {/* ── Boutons Admin ── */}
        {isAdmin&&(
          <div style={{display:"flex",gap:8,marginBottom:16,flexWrap:"wrap"}}>
            {/* Recharge crédit Claude */}
            <button onClick={()=>window.open("https://console.anthropic.com/settings/billing","_blank")}
              style={{display:"flex",alignItems:"center",gap:6,padding:"8px 14px",borderRadius:10,border:"1px solid #e879f9",background:"linear-gradient(135deg,#4c0519,#1e0010)",color:"white",cursor:"pointer",fontSize:12,fontWeight:700,flex:1}}>
              <span style={{fontSize:16}}>🤖</span>
              <div style={{textAlign:"left"}}>
                <div>Recharger crédit Claude</div>
                <div style={{fontSize:10,opacity:0.7,fontWeight:400}}>console.anthropic.com</div>
              </div>
              <span style={{marginLeft:"auto",fontSize:14}}>↗</span>
            </button>
            {/* Modifier slides */}
            <button onClick={()=>setShowSlideEditor(v=>!v)}
              style={{display:"flex",alignItems:"center",gap:6,padding:"8px 14px",borderRadius:10,border:"1px solid #38bdf8",background:showSlideEditor?"#0c4a6e":"#f0f9ff",color:showSlideEditor?"white":"#0891b2",cursor:"pointer",fontSize:12,fontWeight:700,flex:1}}>
              <span style={{fontSize:16}}>🖼️</span>
              <div style={{textAlign:"left"}}>
                <div>{showSlideEditor?"Fermer l'éditeur":"Modifier le carousel"}</div>
                <div style={{fontSize:10,opacity:0.7,fontWeight:400}}>{slides.length} slide(s)</div>
              </div>
            </button>
          </div>
        )}

        {/* ── Éditeur de slides (admin) ── */}
        {isAdmin&&showSlideEditor&&(
          <div style={{background:"#f8fafc",border:"1px solid #e2e8f0",borderRadius:12,padding:14,marginBottom:16}}>
            <div style={{fontWeight:700,fontSize:13,marginBottom:10,color:"#1e293b"}}>🖼️ Gestion des slides du carousel</div>
            {/* Liste des slides */}
            <div style={{display:"flex",flexDirection:"column",gap:6,marginBottom:10}}>
              {slides.map((s,i)=>(
                <div key={i} style={{display:"flex",alignItems:"center",gap:8,padding:"8px 10px",background:s.bg,borderRadius:8,cursor:"pointer",border:editSlide?.index===i?"2px solid white":"2px solid transparent"}}
                  onClick={()=>setEditSlide({index:i,...s})}>
                  <span style={{fontSize:20}}>{s.emoji}</span>
                  <div style={{flex:1,color:"white"}}>
                    <div style={{fontWeight:700,fontSize:12}}>{s.title}</div>
                    <div style={{fontSize:10,opacity:0.7}}>{s.sub?.substring(0,50)}...</div>
                  </div>
                  <button onClick={e=>{e.stopPropagation();handleDeleteSlide(i);}}
                    style={{background:"rgba(255,0,0,0.3)",border:"none",color:"white",borderRadius:6,padding:"2px 7px",cursor:"pointer",fontSize:11}}>🗑️</button>
                </div>
              ))}
            </div>
            <div style={{display:"flex",gap:6,marginBottom:editSlide?12:0}}>
              <button onClick={handleAddSlide} style={{padding:"6px 12px",borderRadius:8,border:"1px dashed #94a3b8",background:"white",color:"#64748b",cursor:"pointer",fontSize:12,flex:1}}>+ Ajouter un slide</button>
              <button onClick={handleResetSlides} style={{padding:"6px 12px",borderRadius:8,border:"1px solid #fcd34d",background:"#fef9c3",color:"#92400e",cursor:"pointer",fontSize:12}}>↺ Réinitialiser</button>
            </div>
            {/* Formulaire d'édition */}
            {editSlide&&(
              <div style={{background:"white",border:"1px solid #e2e8f0",borderRadius:10,padding:12,marginTop:8}}>
                <div style={{fontWeight:700,fontSize:12,marginBottom:8,color:"#1e293b"}}>✏️ Modifier le slide {editSlide.index+1}</div>
                {/* Photo de fond */}
                <div style={{marginBottom:8}}>
                  <div style={{fontSize:11,color:"#64748b",marginBottom:3}}>📷 Photo de fond <span style={{color:"#94a3b8"}}>(remplace le dégradé)</span></div>
                  {editSlide.imageUrl ? (
                    <div style={{position:"relative",borderRadius:8,overflow:"hidden",marginBottom:4}}>
                      <img src={editSlide.imageUrl} alt="slide" style={{width:"100%",height:90,objectFit:"cover",display:"block"}}/>
                      <button onClick={handleDeletePhoto}
                        style={{position:"absolute",top:6,right:6,background:"rgba(239,68,68,0.9)",border:"none",color:"white",borderRadius:6,padding:"3px 8px",cursor:"pointer",fontSize:11,fontWeight:700}}>
                        🗑️ Supprimer
                      </button>
                    </div>
                  ) : (
                    <label style={{display:"flex",alignItems:"center",gap:8,padding:"10px 12px",border:"2px dashed #cbd5e1",borderRadius:8,cursor:"pointer",background:"#f8fafc"}}>
                      <input type="file" accept="image/*" style={{display:"none"}}
                        onChange={e=>e.target.files[0]&&handlePhotoUpload(e.target.files[0])}/>
                      {uploadingPhoto
                        ? <span style={{fontSize:12,color:"#0891b2"}}>⏳ Upload en cours...</span>
                        : <><span style={{fontSize:18}}>📷</span><span style={{fontSize:12,color:"#64748b"}}>Cliquer pour choisir une image</span></>}
                    </label>
                  )}
                </div>
                {/* Emoji — masqué si photo */}
                {!editSlide.imageUrl&&(
                  <div style={{marginBottom:8}}>
                    <div style={{fontSize:11,color:"#64748b",marginBottom:3}}>Emoji (si pas de photo)</div>
                    <input value={editSlide.emoji||""} onChange={e=>setEditSlide(v=>({...v,emoji:e.target.value}))}
                      style={{width:"100%",padding:"6px 8px",border:"1px solid #e2e8f0",borderRadius:6,fontSize:20,boxSizing:"border-box"}}/>
                  </div>
                )}
                <div style={{marginBottom:8}}>
                  <div style={{fontSize:11,color:"#64748b",marginBottom:3}}>Titre</div>
                  <input value={editSlide.title||""} onChange={e=>setEditSlide(v=>({...v,title:e.target.value}))}
                    style={{width:"100%",padding:"6px 8px",border:"1px solid #e2e8f0",borderRadius:6,fontSize:12,boxSizing:"border-box"}}/>
                </div>
                <div style={{marginBottom:8}}>
                  <div style={{fontSize:11,color:"#64748b",marginBottom:3}}>Sous-titre</div>
                  <textarea value={editSlide.sub||""} onChange={e=>setEditSlide(v=>({...v,sub:e.target.value}))}
                    rows={2} style={{width:"100%",padding:"6px 8px",border:"1px solid #e2e8f0",borderRadius:6,fontSize:11,resize:"vertical",boxSizing:"border-box"}}/>
                </div>
                <div style={{marginBottom:8}}>
                  <div style={{fontSize:11,color:"#64748b",marginBottom:3}}>Couleur d'accentuation</div>
                  <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                    {ACCENT_COLORS.map(c=>(
                      <div key={c} onClick={()=>setEditSlide(v=>({...v,accent:c}))}
                        style={{width:24,height:24,borderRadius:"50%",background:c,cursor:"pointer",
                          border:editSlide.accent===c?"3px solid #1e293b":"2px solid transparent"}}/>
                    ))}
                  </div>
                </div>
                {/* Dégradé — masqué si photo */}
                {!editSlide.imageUrl&&(
                  <div style={{marginBottom:10}}>
                    <div style={{fontSize:11,color:"#64748b",marginBottom:3}}>Dégradé de fond</div>
                    <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                      {BG_GRADIENTS.map(g=>(
                        <div key={g} onClick={()=>setEditSlide(v=>({...v,bg:g}))}
                          style={{width:32,height:24,borderRadius:4,background:g,cursor:"pointer",
                            border:editSlide.bg===g?"3px solid #0891b2":"2px solid transparent"}}/>
                      ))}
                    </div>
                  </div>
                )}
                {/* Aperçu */}
                <div style={{background:editSlide.imageUrl?"none":editSlide.bg,borderRadius:8,padding:"10px 14px",marginBottom:10,textAlign:"center",
                  ...(editSlide.imageUrl?{backgroundImage:`url(${editSlide.imageUrl})`,backgroundSize:"cover",backgroundPosition:"center"}:{})}}>
                  {!editSlide.imageUrl&&<div style={{fontSize:28}}>{editSlide.emoji}</div>}
                  <div style={{color:"white",fontWeight:700,fontSize:12,textShadow:"0 1px 3px rgba(0,0,0,0.5)"}}>{editSlide.title}</div>
                  <div style={{height:2,background:editSlide.accent,width:40,margin:"6px auto 0",borderRadius:99}}/>
                </div>
                <div style={{display:"flex",gap:6}}>
                  <button onClick={handleSaveSlide} disabled={uploadingPhoto}
                    style={{flex:1,padding:"8px",borderRadius:8,border:"none",background:uploadingPhoto?"#cbd5e1":"#0891b2",color:"white",cursor:uploadingPhoto?"not-allowed":"pointer",fontWeight:700,fontSize:12}}>
                    {uploadingPhoto?"⏳ Upload...":"✅ Sauvegarder"}
                  </button>
                  <button onClick={()=>setEditSlide(null)}
                    style={{padding:"8px 12px",borderRadius:8,border:"1px solid #e2e8f0",background:"white",color:"#64748b",cursor:"pointer",fontSize:12}}>Annuler</button>
                </div>
              </div>
            )}
          </div>
        )}
      {/* KPIs */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:16}}>
        {kpis.map(k=>(
          <div key={k.label} style={{...card,padding:14}}>
            <div style={{fontSize:22}}>{k.icon}</div>
            <div style={{fontSize:24,fontWeight:800,color:k.color,margin:"4px 0"}}>{k.value}</div>
            <div style={{fontSize:11,color:"#64748b"}}>{k.label}</div>
          </div>
        ))}
      </div>

      {/* Alerte stocks bas */}
      {lowStock.length>0&&(
        <div style={{background:"#fef3c7",border:"1px solid #fcd34d",borderRadius:10,padding:14,marginBottom:16}}>
          <div style={{fontWeight:700,color:"#92400e",marginBottom:8}}>⚠️ Stocks Bas ({lowStock.length})</div>
          {lowStock.map(p=>(
            <div key={p.id} style={{display:"flex",justifyContent:"space-between",fontSize:12,padding:"4px 0",borderBottom:"1px solid rgba(0,0,0,0.05)"}}>
              <span style={{color:"#78350f"}}>{p.name}</span>
              <span style={{fontWeight:700,color:"#ef4444"}}>{stock[p.id]||0} u.</span>
            </div>
          ))}
        </div>
      )}

      {/* Niveaux stock */}
      <div style={{...card,marginBottom:12}}>
        <div style={{fontWeight:700,color:"#1e293b",marginBottom:12,fontSize:14}}>📈 Niveaux de stock</div>
        {supProds.slice(0,6).map(p=>{
          const qty=stock[p.id]||0;
          const pct=Math.min(100,(qty/250)*100);
          return(
            <div key={p.id} style={{marginBottom:10}}>
              <div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:3}}>
                <span style={{color:"#374151",fontWeight:500}}>{p.name}</span>
                <span style={{fontWeight:700,color:qty<30?"#ef4444":"#059669"}}>{qty}</span>
              </div>
              <div style={{height:5,background:"#f1f5f9",borderRadius:99}}>
                <div style={{height:"100%",width:pct+"%",background:qty<30?"#ef4444":"#38bdf8",borderRadius:99,transition:"width 0.5s"}}/>
              </div>
            </div>
          );
        })}
      </div>

      {/* Activités récentes */}
      <div style={{...card}}>
        <div style={{fontWeight:700,color:"#1e293b",marginBottom:12,fontSize:14}}>🕐 Activités récentes</div>
        {[...entries,...returns].filter(x=>!activeSupplier||x.supplierId===activeSupplier?.id).slice(0,5).map(x=>(
          <div key={x.id} style={{display:"flex",justifyContent:"space-between",padding:"7px 0",borderBottom:"1px solid #f8fafc",fontSize:12}}>
            <div><span style={{marginRight:6}}>{x.type==="entry"?"📥":"↩️"}</span><span style={{color:"#374151"}}>Bon #{x.id.slice(-5)}</span></div>
            <span style={{color:"#94a3b8"}}>{fmtDate(x.date)}</span>
          </div>
        ))}
        {entries.length===0&&returns.length===0&&<div style={{color:"#94a3b8",fontSize:13,textAlign:"center",padding:16}}>Aucune activité</div>}
      </div>
      </div>{/* end padding:16 */}
    </div>
  );
}

// ─────────────────────────────────────────────
// DOCUMENT FORM (Bon d'entrée / retour)
// ─────────────────────────────────────────────
function DocumentForm({type,store,activeSupplier,activeDepot,ai,onNav,currentUser}){
  const isEntry=type==="entry";
  const suppDepots=activeSupplier ? store.depots.filter(d=>d.supplierId===activeSupplier.id) : store.depots;
  const suppProds=activeSupplier ? store.products.filter(p=>p.supplierId===activeSupplier.id) : store.products;

  const blank=()=>({
    reference:`BON-${isEntry?"ENT":"RET"}-${genId()}`,
    supplierId: activeSupplier?.id||"",
    depotId: suppDepots[0]?.id||"",
    date: new Date().toISOString().split("T")[0],
    notes:"",
    items:[{productId:"",qty:"",unitPrice:"",lot:"",expiry:""}],
  });
  const [form,setForm]=useState(blank);
  const [saved,setSaved]=useState(false);
  const [scanning,setScanning]=useState(false);
  const [scanMsg,setScanMsg]=useState("");
  const fileRef=useRef(null);

  const [printBon,setPrintBon]=useState(null);

  // sync supplier
  useEffect(()=>{ if(activeSupplier) setForm(f=>({...f,supplierId:activeSupplier.id,depotId:suppDepots[0]?.id||f.depotId})); },[activeSupplier?.id]);

  // Derniers bons de ce type pour ce fournisseur
  const recentBons = (isEntry ? store.entries : store.returns)
    .filter(b => !activeSupplier || b.supplierId === activeSupplier?.id)
    .slice(0, 3);

  const addItem=()=>setForm(f=>({...f,items:[...f.items,{productId:"",qty:"",unitPrice:"",lot:"",expiry:""}]}));
  const removeItem=i=>setForm(f=>({...f,items:f.items.filter((_,idx)=>idx!==i)}));
  const setItem=(i,field,val)=>setForm(f=>({...f,items:f.items.map((it,idx)=>idx===i?{...it,[field]:val}:it)}));

  // Auto-fill price when product is selected
  const selectProduct=(i,productId)=>{
    const prod=suppProds.find(p=>p.id===productId);
    setForm(f=>({
      ...f,
      items:f.items.map((it,idx)=>idx===i
        ? {...it, productId, unitPrice: prod?.price ? String(prod.price) : it.unitPrice}
        : it
      )
    }));
  };

  const handleSave=()=>{
    const doc={...form,items:form.items.filter(it=>it.productId&&it.qty),supplierId:form.supplierId||activeSupplier?.id};
    if(isEntry) store.addEntry(doc); else store.addReturn(doc);
    setSaved(true); setForm(blank());
    setTimeout(()=>setSaved(false),3000);
  };

  const [bonScanResult, setBonScanResult] = useState(null);
  const [bonReviewOpen, setBonReviewOpen] = useState(false);
  const [deletingBon,   setDeletingBon]   = useState(null);

  const handleScan=async(file)=>{
    if(!file) return;
    setScanning(true);
    setScanMsg("📄 Analyse du document en cours...");
    try {
      const result = await scanDocumentWithAI(file, suppProds);
      if(result.success && result.items?.length > 0){
        setScanMsg("");
        setBonScanResult(result);
        setBonReviewOpen(true); // ouvrir révision
      } else {
        setScanMsg("⚠️ " + (result.error || "Aucun article détecté dans le document."));
      }
    } catch(e) {
      setScanMsg("❌ Erreur scan : " + e.message);
    }
    setScanning(false);
  };

  const handleConfirmBonScan = async (selectedRows) => {
    setBonReviewOpen(false);
    // Nouveaux produits non reconnus → proposer création
    const newProds = selectedRows.filter(r => r.isNew && r.productName?.trim());
    let newlyCreated = [];
    for (const np of newProds) {
      const id = await store.addProduct({
        name: np.productName.trim(),
        price: Number(np.unitPrice||0),
        unit: np.unit||"Boîte",
        supplierId: activeSupplier?.id||"",
      });
      newlyCreated.push({ ...np, productId: id });
    }
    // Construire les lignes du bon
    const items = selectedRows.map(r => {
      const prodId = r.isNew
        ? (newlyCreated.find(nc=>nc.productName===r.productName)?.productId||"")
        : r.productId;
      const knownProd = suppProds.find(p=>p.id===prodId);
      return {
        productId: prodId,
        qty:       String(r.qty||""),
        unitPrice: r.unitPrice ? String(r.unitPrice) : knownProd?.price ? String(knownProd.price) : "",
        lot:       r.lot||"",
        expiry:    r.expiry||"",
      };
    }).filter(it => it.productId);
    setForm(f=>({
      ...f,
      reference: bonScanResult?.reference || f.reference,
      notes: "Extrait du document scanné",
      items: items.length > 0 ? items : f.items,
    }));
    const nNew = newProds.length;
    setScanMsg("✅ " + items.length + " article(s) importé(s)" + (nNew>0 ? " · " + nNew + " nouveau(x) produit(s) créé(s)" : ""));
    setTimeout(()=>setScanMsg(""), 8000);
    setBonScanResult(null);
  };

  return(
    <div style={{padding:16}}>
      {/* Confirm delete bon */}
      <ConfirmDelete open={!!deletingBon} onClose={()=>setDeletingBon(null)}
        label={deletingBon?.reference||""}
        onConfirm={()=>{ if(isEntry) store.deleteEntry(deletingBon.id); else store.deleteReturn(deletingBon.id); }}/>
      {/* Modale révision scan bon */}
      <ScanReviewModal
        open={bonReviewOpen}
        onClose={()=>{setBonReviewOpen(false);setBonScanResult(null);}}
        scanResult={bonScanResult}
        allProducts={store.products}
        activeSupplier={activeSupplier}
        onConfirm={handleConfirmBonScan}
        mode="bon"
      />
      <PageHeader
        pageId={isEntry?"entrees":"retours"}
        title={isEntry?"📥 Bon d'Entrée":"↩️ Bon de Retour"}
        subtitle={isEntry?"Réception de produits pharmaceutiques · "+(activeSupplier?.name||""):"Retour fournisseur · "+(activeSupplier?.name||"")}>
        <button onClick={()=>fileRef.current?.click()} style={{...btn(),background:"rgba(255,255,255,0.15)",color:"white",border:"1px solid rgba(255,255,255,0.3)",fontSize:12}}>
          {scanning?"⏳ Analyse...":"📄 Scanner"}
        </button>
        <input ref={fileRef} type="file" accept=".pdf,.xlsx,.jpg,.jpeg,.png" style={{display:"none"}} onChange={e=>{handleScan(e.target.files[0]);e.target.value="";}} />
      </PageHeader>

      {!activeSupplier&&<Alert type="warn">⚠️ Aucun fournisseur actif. Sélectionnez un fournisseur via le menu ou la barre du haut.</Alert>}
      {saved&&<Alert type="success">✅ Bon enregistré avec succès !</Alert>}


      <div style={{...card,marginBottom:12}}>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:8}}>
          <div>
            <label style={label}>Référence</label>
            <input style={input} value={form.reference} onChange={e=>setForm(f=>({...f,reference:e.target.value}))}/>
          </div>
          <div>
            <label style={label}>Date</label>
            <input style={input} type="date" value={form.date} onChange={e=>setForm(f=>({...f,date:e.target.value}))}/>
          </div>
        </div>

        <div style={{marginBottom:12}}>
          <label style={label}>Fournisseur</label>
          <div style={{...input,background:"#f8fafc",color:activeSupplier?"#1e293b":"#94a3b8",display:"flex",alignItems:"center"}}>
            {activeSupplier ? `🏢 ${activeSupplier.name}` : "— Aucun fournisseur actif —"}
          </div>
        </div>

        <div>
          <label style={label}>Dépôt</label>
          <select style={input} value={form.depotId} onChange={e=>setForm(f=>({...f,depotId:e.target.value}))}>
            <option value="">Sélectionner un dépôt...</option>
            {suppDepots.map(d=><option key={d.id} value={d.id}>{d.name} — {d.location}</option>)}
          </select>
        </div>
      </div>

      {/* Articles */}
      <div style={{...card,marginBottom:12}}>
        <div style={{fontWeight:700,color:"#1e293b",marginBottom:12,fontSize:14}}>Articles</div>
        {form.items.map((it,i)=>(
          <div key={i} style={{background:"#f8fafc",borderRadius:8,padding:12,marginBottom:8}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
              <div style={{fontSize:12,fontWeight:700,color:"#64748b"}}>Article {i+1}</div>
              {form.items.length>1&&<button onClick={()=>removeItem(i)} style={{...btn(),background:"#fee2e2",color:"#ef4444",padding:"3px 8px",fontSize:12}}>✕</button>}
            </div>
            <div style={{marginBottom:8}}>
              <label style={label}>Produit</label>
              <select style={input} value={it.productId} onChange={e=>selectProduct(i,e.target.value)}>
                <option value="">Sélectionner un produit...</option>
                {suppProds.map(p=><option key={p.id} value={p.id}>{p.name} — {Number(p.price||0).toLocaleString("fr-FR")} FCFA</option>)}
              </select>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
              <div><label style={label}>Quantité</label><input style={input} type="number" min="0" value={it.qty} onChange={e=>setItem(i,"qty",e.target.value)}/></div>
              <div>
                <label style={label}>Prix Unit. (FCFA) <span style={{fontWeight:400,color:"#94a3b8",fontSize:10}}>auto</span></label>
                <input style={{...input,background:it.unitPrice?"#f0fdf4":"white"}} type="number" min="0" value={it.unitPrice} onChange={e=>setItem(i,"unitPrice",e.target.value)} placeholder="Auto depuis produit"/>
              </div>
              <div><label style={label}>N° Lot</label><input style={input} value={it.lot} onChange={e=>setItem(i,"lot",e.target.value)}/></div>
              <div><label style={label}>Expiration</label><input style={input} type="date" value={it.expiry} onChange={e=>setItem(i,"expiry",e.target.value)}/></div>
            </div>
          </div>
        ))}
        <button onClick={addItem} style={{...btn(),background:"#f0f9ff",color:"#0891b2",border:"1px dashed #bae6fd",width:"100%",marginTop:4}}>+ Ajouter un article</button>
      </div>

      <div style={{...card,marginBottom:14}}>
        <label style={label}>Notes</label>
        <textarea style={{...input,height:70,resize:"vertical"}} value={form.notes} onChange={e=>setForm(f=>({...f,notes:e.target.value}))}/>
      </div>

      <button onClick={handleSave} disabled={!activeSupplier||!form.depotId} style={{...btn(),background:!activeSupplier?"#cbd5e1":"linear-gradient(135deg,#0891b2,#0e7490)",color:"white",width:"100%",padding:12,fontSize:14}}>
        💾 Enregistrer le Bon
      </button>

      {/* Bons récents avec impression */}
      {recentBons.length > 0 && (
        <div style={{marginTop:20}}>
          <div style={{fontWeight:700,color:"#1e293b",fontSize:13,marginBottom:10}}>
            {isEntry ? "📥" : "↩️"} Bons récents
          </div>
          <div style={{display:"flex",flexDirection:"column",gap:8}}>
            {recentBons.map(b => {
              const depot = store.depots.find(d => d.id === b.depotId);
              return (
                <div key={b.id} style={{...card,padding:12,display:"flex",justifyContent:"space-between",alignItems:"center",gap:10}}>
                  <div style={{flex:1}}>
                    <div style={{fontWeight:700,color:"#1e293b",fontSize:12}}>{b.reference}</div>
                    <div style={{fontSize:11,color:"#64748b"}}>{fmtDate(b.date)} · {depot?.name||"—"} · {b.items?.length||0} article(s)</div>
                    {b.createdByName&&<div style={{fontSize:10,color:"#94a3b8"}}>👤 {b.createdByName}</div>}
                  </div>
                  <div style={{display:"flex",gap:5}}>
                    <button onClick={()=>setPrintBon(b)} style={{...btn(),background:"#f0f9ff",color:"#0891b2",border:"1px solid #bae6fd",padding:"5px 8px",fontSize:11}}>🖨️</button>
                    <button onClick={()=>{const rows=(b.items||[]).map(it=>{const p=store.products.find(x=>x.id===it.productId);return[p?.name||it.productId,it.qty,Number(it.unitPrice||0),it.lot||"",it.expiry||""];});downloadExcel(b.reference+".xlsx",rows,["Produit","Qté","Prix unit. FCFA","Lot","Expiration"]);}} style={{...btn(),background:"#f0fdf4",color:"#059669",border:"1px solid #bbf7d0",padding:"5px 7px",fontSize:11}}>⬇️</button>
                    {can(currentUser,isEntry?"entrees":"retours","d")&&<button onClick={()=>setDeletingBon(b)} style={{...btn(),background:"#fee2e2",color:"#ef4444",padding:"5px 7px",fontSize:11}}>🗑️</button>}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Modale impression bon */}
      {printBon && (
        <PrintModal open={!!printBon} onClose={()=>setPrintBon(null)} title={"Bon " + (printBon?.reference||"")}>
          <BonPrint
            bon={printBon}
            suppName={store.suppliers.find(s=>s.id===printBon.supplierId)?.name||activeSupplier?.name||"—"}
            depotName={store.depots.find(d=>d.id===printBon.depotId)?.name||"—"}
            products={store.products}
          />
        </PrintModal>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────
// INVENTORY PAGE — par dépôt + consolidation fournisseur
// ─────────────────────────────────────────────
function InventoryPage({store,activeSupplier,currentUser}){
  const DRAFT_KEY = `inv_draft_${activeSupplier?.id||"global"}`;

  // mode: "choose" | "by-depot" | "consolidated"
  const [mode,setMode]=useState("choose");
  const [depotId,setDepotId]=useState("");
  // depotPhysical = { depotId: { productId: qty } }
  const [depotPhysical,setDepotPhysical]=useState({});
  const [result,setResult]=useState(null); // consolidated rows
  const [depotResults,setDepotResults]=useState({}); // { depotId: rows }
  const [step,setStep]=useState(1); // 1=choose depot 2=saisie 3=results 4=done
  const [scanning,setScanning]=useState(false);
  const [scanMsg,setScanMsg]=useState("");
  const [printList,setPrintList]=useState(false);
  const [showOldStock,setShowOldStock]=useState(true);
  const [editingResult,setEditingResult]=useState(false); // mode édition résultats
  const fileRef=useRef(null);

  // ── Restaurer le brouillon au montage ──
  useEffect(()=>{
    try {
      const saved = localStorage.getItem(DRAFT_KEY);
      if(saved){
        const draft = JSON.parse(saved);
        if(draft.depotPhysical) setDepotPhysical(draft.depotPhysical);
        if(draft.depotResults)  setDepotResults(draft.depotResults);
        if(draft.result)        setResult(draft.result);
        if(draft.step && draft.step < 4) setStep(draft.step);
        if(draft.depotId)       setDepotId(draft.depotId);
      }
    } catch(e){}
  // eslint-disable-next-line react-hooks/exhaustive-deps
  },[activeSupplier?.id]);

  // ── Sauvegarder le brouillon à chaque changement ──
  useEffect(()=>{
    if(step===4){ localStorage.removeItem(DRAFT_KEY); return; }
    try {
      localStorage.setItem(DRAFT_KEY, JSON.stringify({
        depotPhysical, depotResults, result, step, depotId
      }));
    } catch(e){}
  // eslint-disable-next-line react-hooks/exhaustive-deps
  },[depotPhysical, depotResults, result, step, depotId]);

  const suppDepots = activeSupplier ? store.depots.filter(d=>d.supplierId===activeSupplier.id) : store.depots;
  // All products of this supplier (no depotId filter — same products in all depots)
  const suppProds = activeSupplier ? store.products.filter(p=>p.supplierId===activeSupplier.id) : store.products;

  const m=new Date().getMonth(), y=new Date().getFullYear();

  // Compute rows for one depot
  const computeDepot=(dId, phys)=>{
    const mEnts=store.entries.filter(e=>new Date(e.date).getMonth()===m&&new Date(e.date).getFullYear()===y&&e.depotId===dId&&(!activeSupplier||e.supplierId===activeSupplier.id));
    const mRets=store.returns.filter(r=>new Date(r.date).getMonth()===m&&new Date(r.date).getFullYear()===y&&r.depotId===dId&&(!activeSupplier||r.supplierId===activeSupplier.id));
    return suppProds.map(p=>{
      const old=store.stock[p.id]||0;
      const ent=mEnts.reduce((s,e)=>s+(e.items?.find(i=>i.productId===p.id)?.qty||0)*1,0);
      const ret=mRets.reduce((s,r)=>s+(r.items?.find(i=>i.productId===p.id)?.qty||0)*1,0);
      const nw=Number((phys||{})[p.id]||0);
      const sold=Math.max(0,old+ent-ret-nw);
      return{product:p,old,ent,ret,nw,sold,depot:store.depots.find(d=>d.id===dId)?.name||dId};
    });
  };

  // Consolidated: sum across all depots
  const consolidate=(allDepotResults)=>{
    const byProd={};
    Object.values(allDepotResults).forEach(rows=>{
      rows.forEach(row=>{
        if(!byProd[row.product.id]) byProd[row.product.id]={product:row.product,old:0,ent:0,ret:0,nw:0,sold:0,depotBreakdown:{}};
        byProd[row.product.id].old+=row.old;
        byProd[row.product.id].ent+=row.ent;
        byProd[row.product.id].ret+=row.ret;
        byProd[row.product.id].nw+=row.nw;
        byProd[row.product.id].sold+=row.sold;
        byProd[row.product.id].depotBreakdown[row.depot]=row.nw;
      });
    });
    return Object.values(byProd);
  };

  const handleStartDepot=()=>{
    if(!depotId) return;
    setStep(2);
    setScanMsg("");
  };

  const [invScanResult,  setInvScanResult]  = useState(null);
  const [invReviewOpen,  setInvReviewOpen]  = useState(false);

  const handleScan=async(file)=>{
    if(!file) return;
    setScanning(true); setScanMsg("📄 Analyse du document en cours...");
    if(fileRef.current) fileRef.current.value="";
    try {
      const res=await scanDocumentWithAI(file, suppProds);
      if(res.success && res.items?.length > 0){
        setScanMsg("");
        setInvScanResult(res);
        setInvReviewOpen(true); // ouvrir révision
      } else {
        setScanMsg("⚠️ " + (res.error || "Aucune quantité détectée. Saisissez manuellement."));
      }
    } catch(e) {
      setScanMsg("❌ Erreur : " + e.message);
    }
    setScanning(false);
  };

  const handleConfirmInvScan = async (selectedRows) => {
    setInvReviewOpen(false);
    // Nouveaux produits → créer d'abord
    const newProds = selectedRows.filter(r => r.isNew && r.productName?.trim());
    const createdIds = {};
    for (const np of newProds) {
      const id = await store.addProduct({
        name: np.productName.trim(),
        price: Number(np.unitPrice||0),
        unit: np.unit||"Boîte",
        supplierId: activeSupplier?.id||"",
      });
      createdIds[np.productName] = id;
    }
    // Remplir les quantités physiques
    const phys = {};
    selectedRows.forEach(r => {
      const pid = r.isNew ? (createdIds[r.productName]||"") : r.productId;
      if(pid && r.qty) phys[pid] = String(r.qty);
    });
    setDepotPhysical(prev=>({...prev,[depotId]:{...(prev[depotId]||{}),...phys}}));
    const nNew = newProds.length;
    setScanMsg("✅ " + Object.keys(phys).length + " quantité(s) renseignée(s)"
      + (nNew>0 ? " · " + nNew + " nouveau(x) produit(s) créé(s)" : ""));
    setInvScanResult(null);
  };

  const handleComputeDepot=()=>{
    const phys=depotPhysical[depotId]||{};
    if(depotId==="__global__"){
      // Global mode: treat as single virtual depot containing all products
      const rows=suppProds.map(p=>{
        const m=new Date().getMonth(), y=new Date().getFullYear();
        const mEnts=store.entries.filter(e=>new Date(e.date).getMonth()===m&&new Date(e.date).getFullYear()===y&&(!activeSupplier||e.supplierId===activeSupplier.id));
        const mRets=store.returns.filter(r=>new Date(r.date).getMonth()===m&&new Date(r.date).getFullYear()===y&&(!activeSupplier||r.supplierId===activeSupplier.id));
        const old=store.stock[p.id]||0;
        const ent=mEnts.reduce((s,e)=>s+(e.items?.find(i=>i.productId===p.id)?.qty||0)*1,0);
        const ret=mRets.reduce((s,r)=>s+(r.items?.find(i=>i.productId===p.id)?.qty||0)*1,0);
        const nw=Number((phys||{})[p.id]||0);
        const sold=Math.max(0,old+ent-ret-nw);
        return{product:p,old,ent,ret,nw,sold,depot:"Global",depotBreakdown:{"Global":nw}};
      });
      const globalResult=rows.map(r=>({...r}));
      setResult(globalResult);
      setDepotResults({"__global__":rows});
      setStep(3);
    } else {
      const rows=computeDepot(depotId,phys);
      const newDR={...depotResults,[depotId]:rows};
      setDepotResults(newDR);
      setResult(consolidate(newDR));
      setStep(3);
    }
  };

  const handleAddAnotherDepot=()=>{
    setDepotId(""); setStep(1);
  };

  const saveAndFinish=async()=>{
    const inv={
      month:monthLabel(), supplierId:activeSupplier?.id,
      data:result,
      depotResults:depotResults,
      totalSold:result.reduce((s,r)=>s+r.sold,0),
    };
    await store.addInventory(inv);
    // Mettre à jour le stock UNIQUEMENT pour les produits qui ont été inventoriés
    // (nw > 0 ou explicitement saisi), les autres restent inchangés
    for(const row of (result||[])){
      if(!row.product?.id) continue;
      // Vérifier si ce produit a été saisi dans au moins un dépôt
      const wasCounted = Object.values(depotPhysical).some(phys => phys[row.product.id] !== undefined);
      if(wasCounted && row.nw >= 0){
        try { await store.setStockForProduct(row.product.id, row.nw); } catch(e){ console.warn("Stock update error:", e); }
      }
      // Si non inventorié → stock inchangé
    }
    setStep(4);
  };

  const createInvoice=()=>{
    if(!result) return;
    const items=result.filter(r=>r.sold>0).map(r=>({
      productId:r.product.id, productName:r.product.name,
      qty:r.sold, unitPrice:r.product.price||0, total:r.sold*(r.product.price||0),
    }));
    store.addInvoice({
      month:monthLabel(), supplierId:activeSupplier?.id,
      supplier:activeSupplier?.name||"—",
      reference:"FACT-"+genId(), items,
      total:items.reduce((s,i)=>s+i.total,0),
    });
    alert("✅ Facture générée avec les prix FCFA !");
  };

  const thS={padding:"7px 9px",textAlign:"left",fontSize:11,fontWeight:700,color:"#64748b",borderBottom:"2px solid #e2e8f0",background:"#f8fafc"};
  const tdS={padding:"7px 9px",borderBottom:"1px solid #f1f5f9",fontSize:12};

  const completedDepots=Object.keys(depotResults);
  const remainingDepots=suppDepots.filter(d=>!completedDepots.includes(d.id));

  return(
    <div style={{padding:16}}>
      <PageHeader pageId="inventaire" title="🗂️ Inventaire Mensuel"
        subtitle={monthLabel() + " · " + (activeSupplier?activeSupplier.name:"Aucun fournisseur sélectionné")}/>

      {!activeSupplier&&<Alert type="warn">⚠️ Sélectionnez un fournisseur pour lancer l'inventaire.</Alert>}

      {/* Bandeau brouillon */}
      {activeSupplier && step>1 && step<4 && (
        <div style={{background:"#fffbeb",border:"1px solid #fcd34d",borderRadius:8,padding:"10px 14px",marginBottom:12,display:"flex",alignItems:"center",justifyContent:"space-between",gap:8}}>
          <div style={{fontSize:12,color:"#92400e",fontWeight:600}}>
            ⏸️ Inventaire en cours — brouillon sauvegardé automatiquement
            {Object.keys(depotResults).length>0&&<span style={{marginLeft:8,fontWeight:400,color:"#78350f"}}>· {Object.keys(depotResults).length} dépôt(s) saisi(s)</span>}
          </div>
          <button onClick={()=>{
            localStorage.removeItem(DRAFT_KEY);
            setDepotPhysical({}); setDepotResults({}); setResult(null); setStep(1); setDepotId("");
          }} style={{background:"#fee2e2",color:"#ef4444",border:"none",borderRadius:6,padding:"4px 10px",cursor:"pointer",fontSize:11,fontWeight:700,flexShrink:0}}>
            🗑️ Réinitialiser
          </button>
        </div>
      )}

      {/* Steps */}
      <div style={{display:"flex",gap:0,marginBottom:20}}>
        {["Dépôt","Saisie","Résultats","Terminé"].map((s,i)=>(
          <div key={s} style={{flex:1,display:"flex",alignItems:"center"}}>
            <div style={{width:26,height:26,borderRadius:"50%",background:step>i?"#0891b2":step===i+1?"#0891b2":"#e2e8f0",color:step>=i+1?"white":"#94a3b8",display:"flex",alignItems:"center",justifyContent:"center",fontWeight:700,fontSize:11,flexShrink:0}}>{i+1}</div>
            <div style={{fontSize:10,marginLeft:4,color:step>=i+1?"#1e293b":"#94a3b8",fontWeight:step===i+1?700:400,whiteSpace:"nowrap"}}>{s}</div>
            {i<3&&<div style={{flex:1,height:2,background:step>i+1?"#0891b2":"#e2e8f0",margin:"0 5px"}}/>}
          </div>
        ))}
      </div>

      {/* STEP 1 — Choisir dépôt */}
      {step===1&&activeSupplier&&(
        <div style={{...card}}>
          <div style={{fontWeight:700,marginBottom:4,fontSize:14}}>Choisir le dépôt à saisir</div>
          <div style={{fontSize:12,color:"#64748b",marginBottom:14}}>
            {suppProds.length} produits · {suppDepots.length} dépôt(s) au total
            {completedDepots.length>0&&<span style={{color:"#059669",marginLeft:8}}>· {completedDepots.length} déjà saisi(s)</span>}
          </div>

          {/* Dépôts déjà saisis */}
          {completedDepots.length>0&&(
            <div style={{marginBottom:14}}>
              <div style={{fontSize:11,fontWeight:700,color:"#059669",marginBottom:6}}>✅ Dépôts saisis :</div>
              {completedDepots.map(dId=>{
                const d=store.depots.find(x=>x.id===dId);
                const rows=depotResults[dId]||[];
                return(
                  <div key={dId} style={{display:"flex",justifyContent:"space-between",background:"#f0fdf4",borderRadius:7,padding:"7px 12px",marginBottom:5,fontSize:12}}>
                    <span style={{fontWeight:600,color:"#1e293b"}}>🏭 {d?.name||dId}</span>
                    <span style={{color:"#059669"}}>Vendus : {rows.reduce((s,r)=>s+r.sold,0)}</span>
                  </div>
                );
              })}
            </div>
          )}

          <select style={input} value={depotId} onChange={e=>setDepotId(e.target.value)}>
            <option value="">-- Choisir un dépôt --</option>
            {suppDepots.map(d=>(
              <option key={d.id} value={d.id}>
                {completedDepots.includes(d.id)?"✅ ":""}{d.name} — {d.location}
              </option>
            ))}
          </select>

          <div style={{display:"flex",gap:8,marginTop:14,flexWrap:"wrap"}}>
            <button onClick={handleStartDepot} disabled={!depotId} style={{...btn(),background:!depotId?"#cbd5e1":"#0891b2",color:"white",flex:1}}>
              Saisie par dépôt →
            </button>
            <button onClick={()=>{setDepotId("__global__");setStep(2);setScanMsg("");}} style={{...btn(),background:"#7c3aed",color:"white",flex:1}}>
              🌐 Tous dépôts (global)
            </button>
            {completedDepots.length>0&&(
              <button onClick={()=>setStep(3)} style={{...btn(),background:"#059669",color:"white"}}>
                Voir consolidation →
              </button>
            )}
          </div>
        </div>
      )}

      {/* STEP 2 — Saisie physique du dépôt */}
      {step===2&&(
        <div>
          <div style={{...card,marginBottom:12}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4}}>
              <div style={{fontWeight:700,fontSize:14}}>
                {depotId==="__global__"?"🌐 Inventaire Global (tous dépôts)":"🏭 "+( store.depots.find(d=>d.id===depotId)?.name||"Dépôt")+" — Stock physique"}
              </div>
              <button onClick={()=>setStep(1)} style={{...btn(),background:"#f1f5f9",color:"#64748b",padding:"5px 10px",fontSize:11}}>← Retour</button>
            </div>
            <div style={{fontSize:12,color:"#64748b",marginBottom:12}}>
              Saisissez la quantité physique constatée pour chaque produit dans ce dépôt
            </div>

            {/* Modale de révision scan inventaire */}
            <ScanReviewModal
              open={invReviewOpen}
              onClose={()=>{setInvReviewOpen(false);setInvScanResult(null);}}
              scanResult={invScanResult}
              allProducts={store.products}
              activeSupplier={activeSupplier}
              onConfirm={handleConfirmInvScan}
              mode="inventory"
            />
            {/* Scanner */}
            <div style={{background:"#fdf4ff",border:"1px solid #e9d5ff",borderRadius:8,padding:12,marginBottom:14}}>
              <div style={{fontSize:12,fontWeight:700,color:"#7c3aed",marginBottom:8}}>📄 Scanner un document</div>
              <div style={{display:"flex",gap:8,flexWrap:"wrap",alignItems:"center"}}>
                <button onClick={()=>fileRef.current?.click()} disabled={scanning} style={{...btn(),background:"#7c3aed",color:"white",fontSize:12,padding:"7px 14px"}}>
                  {scanning?"⏳ Analyse...":"📎 Choisir fichier"}
                </button>
                <button onClick={()=>{if(fileRef.current)fileRef.current.value="";setScanMsg("");setDepotPhysical(prev=>({...prev,[depotId]:{}}));}} style={{...btn(),background:"#fee2e2",color:"#ef4444",fontSize:11,padding:"6px 10px"}}>
                  🔄 Effacer
                </button>
                <input ref={fileRef} type="file" accept=".xlsx,.xls,.pdf,.jpg,.jpeg,.png" style={{display:"none"}}
                  onChange={e=>{if(e.target.files[0]) handleScan(e.target.files[0]);}}/>
              </div>
              {scanMsg&&<Alert type={scanMsg.startsWith("✅")?"success":"warn"}>{scanMsg}</Alert>}
              <div style={{fontSize:10,color:"#94a3b8",marginTop:6}}>Formats : PDF, Excel (.xlsx), Images (JPG/PNG)</div>
            </div>

            {/* Grille saisie */}
            {suppProds.length===0&&<Alert type="warn">Aucun produit pour ce fournisseur.</Alert>}
            {suppProds.map(p=>{
              const phys=depotPhysical[depotId]||{};
              return(
                <div key={p.id} style={{display:"flex",alignItems:"center",gap:10,marginBottom:8,padding:"9px 12px",background:"#f8fafc",borderRadius:8}}>
                  <div style={{flex:1}}>
                    <div style={{fontWeight:600,fontSize:13,color:"#1e293b"}}>{p.name}</div>
                    <div style={{fontSize:11,color:"#64748b"}}>
                      Stock sys. total: <b style={{color:"#0891b2"}}>{store.stock[p.id]||0}</b>
                      {completedDepots.length>0&&(
                        <span style={{color:"#7c3aed",marginLeft:8}}>
                          Déjà saisi: {completedDepots.filter(dId2=>dId2!==depotId).reduce((s,dId2)=>s+Number((depotPhysical[dId2]||{})[p.id]||0),0)}
                        </span>
                      )}
                    </div>
                  </div>
                  <input type="number" min="0"
                    value={phys[p.id]!==undefined?phys[p.id]:""}
                    onChange={e=>setDepotPhysical(prev=>({...prev,[depotId]:{...(prev[depotId]||{}),[p.id]:e.target.value}}))}
                    placeholder="0"
                    style={{width:90,padding:"7px 10px",border:"1.5px solid #e2e8f0",borderRadius:8,fontSize:14,textAlign:"center",outline:"none"}}
                  />
                </div>
              );
            })}
            <button onClick={handleComputeDepot} disabled={suppProds.length===0}
              style={{...btn(),background:"#0891b2",color:"white",width:"100%",marginTop:10}}>
              Valider ce dépôt →
            </button>
          </div>
        </div>
      )}

      {/* STEP 3 — Résultats consolidés */}
      {step===3&&result&&(
        <div>
          {/* Dépôts saisis */}
          <div style={{...card,marginBottom:12,padding:14}}>
            <div style={{fontWeight:700,fontSize:13,marginBottom:10}}>Dépôts inventoriés</div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(140px,1fr))",gap:8}}>
              {completedDepots.map(dId=>{
                const d=store.depots.find(x=>x.id===dId);
                const rows=depotResults[dId]||[];
                return(
                  <div key={dId} style={{background:"#f0fdf4",borderRadius:8,padding:"8px 12px",textAlign:"center"}}>
                    <div style={{fontSize:11,fontWeight:700,color:"#059669"}}>✅ {d?.name}</div>
                    <div style={{fontSize:12,color:"#1e293b",fontWeight:700,marginTop:2}}>{rows.reduce((s,r)=>s+r.nw,0)} unités</div>
                  </div>
                );
              })}
              {remainingDepots.map(d=>(
                <div key={d.id} style={{background:"#fef3c7",borderRadius:8,padding:"8px 12px",textAlign:"center"}}>
                  <div style={{fontSize:11,fontWeight:700,color:"#92400e"}}>⏳ {d.name}</div>
                  <div style={{fontSize:10,color:"#78350f",marginTop:2}}>Non saisi</div>
                </div>
              ))}
            </div>
          </div>

          {/* Tableau consolidé */}
          <div style={{...card,marginBottom:12}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4}}>
              <div style={{fontWeight:700,fontSize:14}}>📊 Consolidation — {monthLabel()}</div>
              <button onClick={()=>setEditingResult(v=>!v)}
                style={{...btn(),background:editingResult?"#0891b2":"#f0f9ff",color:editingResult?"white":"#0891b2",border:"1px solid #bae6fd",fontSize:11,padding:"5px 10px"}}>
                {editingResult?"✅ Terminer édition":"✏️ Modifier"}
              </button>
            </div>
            <div style={{fontSize:11,color:"#64748b",marginBottom:4}}>
              Formule : Vendus = Ancien + Entrées − Retours − Stock Nouveau (somme de tous les dépôts)
            </div>
            <div style={{fontSize:11,color:"#94a3b8",marginBottom:10}}>
              👤 Inventaire en cours par : <b>{store.users?.find(u=>u.id===currentUser?.uid)?.name||currentUser?.name||"—"}</b>
            </div>
            {result.map(row=>(
              <div key={row.product.id} style={{background:"#f8fafc",borderRadius:8,padding:"10px 12px",marginBottom:8,border:editingResult?"1.5px dashed #bae6fd":"1.5px solid transparent"}}>
                <div style={{fontWeight:700,color:"#1e293b",fontSize:13,marginBottom:8}}>{row.product.name}</div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:5,marginBottom:6}}>
                  {[["Ancien",row.old,"#64748b"],["+Entrées",row.ent,"#059669"],["−Retours",row.ret,"#d97706"]].map(([l,v,c])=>(
                    <div key={l} style={{textAlign:"center",background:"white",borderRadius:6,padding:"5px 3px"}}>
                      <div style={{color:c,fontWeight:700,fontSize:14}}>{v}</div>
                      <div style={{color:"#94a3b8",fontSize:10}}>{l}</div>
                    </div>
                  ))}
                  <div style={{textAlign:"center",background:"white",borderRadius:6,padding:"5px 3px"}}>
                    {editingResult ? (
                      <input type="number" min="0"
                        value={row.nw}
                        onChange={e=>{
                          const newNw = Number(e.target.value)||0;
                          const newSold = Math.max(0, row.old+row.ent-row.ret-newNw);
                          setResult(prev=>prev.map(r=>r.product.id===row.product.id ? {...r,nw:newNw,sold:newSold} : r));
                          // Mettre à jour depotPhysical pour cohérence
                          const firstDepot = Object.keys(depotPhysical)[0]||"__global__";
                          setDepotPhysical(prev=>({...prev,[firstDepot]:{...(prev[firstDepot]||{}),[row.product.id]:String(newNw)}}));
                        }}
                        style={{width:"100%",padding:"4px",border:"1.5px solid #0891b2",borderRadius:6,fontSize:14,textAlign:"center",fontWeight:700,color:"#0891b2"}}/>
                    ) : (
                      <div style={{color:"#0891b2",fontWeight:700,fontSize:14}}>{row.nw}</div>
                    )}
                    <div style={{color:"#94a3b8",fontSize:10}}>Nouveau total</div>
                  </div>
                </div>
                {/* Détail par dépôt */}
                {Object.keys(row.depotBreakdown||{}).length>1&&(
                  <div style={{fontSize:10,color:"#7c3aed",marginBottom:4}}>
                    Dépôts : {Object.entries(row.depotBreakdown).map(([d,q])=>`${d}: ${q}`).join(" · ")}
                  </div>
                )}
                <div style={{textAlign:"center"}}>
                  <span style={{background:row.sold>0?"#dcfce7":"#f1f5f9",color:row.sold>0?"#059669":"#94a3b8",padding:"4px 14px",borderRadius:99,fontWeight:700,fontSize:12}}>
                    VENDUS : {row.sold}
                  </span>
                </div>
              </div>
            ))}
            <div style={{background:"#0891b2",color:"white",borderRadius:8,padding:"10px 14px",textAlign:"center",fontWeight:800,fontSize:14,marginTop:8}}>
              Total vendu : {result.reduce((s,r)=>s+r.sold,0)} unités
            </div>
          </div>

          <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:12}}>
            {remainingDepots.length>0&&(
              <button onClick={handleAddAnotherDepot} style={{...btn(),background:"#f0f9ff",color:"#0891b2",border:"1px solid #bae6fd"}}>
                + Ajouter dépôt ({remainingDepots.length} restant{remainingDepots.length>1?"s":""})
              </button>
            )}
            <button onClick={saveAndFinish} style={{...btn(),background:"#059669",color:"white",flex:1}}>💾 Valider inventaire</button>
            <button onClick={createInvoice} style={{...btn(),background:"#7c3aed",color:"white",flex:1}}>🧾 Créer Facture</button>
            <button onClick={()=>{const rows=result.map(r=>[r.product.name,r.old,r.ent,r.ret,r.nw,r.sold]);const hdrs=["Produit","Ancien","Entrées","Retours","Nouveau","Vendus"];downloadExcel("inventaire_"+monthLabel().replace(" ","_")+".xlsx",rows,hdrs);}} style={{...btn(),background:"#f0fdf4",color:"#059669",border:"1px solid #bbf7d0",fontSize:12}}>⬇️ Excel</button>
            <button onClick={()=>{const rows=result.map(r=>[r.product.name,r.old,r.ent,r.ret,r.nw,r.sold]);const hdrs=["Produit","Ancien","Entrées","Retours","Nouveau","Vendus"];const tbl=""+pdfHeader("INVENTAIRE","Période : "+monthLabel())+"<table><tr>"+hdrs.map(h=>"<th>"+h+"</th>").join("")+"</tr>"+rows.map(r=>"<tr>"+r.map(c=>"<td>"+c+"</td>").join("")+"</tr>").join("")+"<tr class=\"total-row\"><td colspan=5>TOTAL VENDU</td><td>"+result.reduce((s,r)=>s+r.sold,0)+"</td></tr></table><div class=\"footer\">Généré le "+new Date().toLocaleDateString("fr-FR")+"</div>";downloadPDF("inventaire_"+monthLabel(),tbl);}} style={{...btn(),background:"#fef3c7",color:"#92400e",border:"1px solid #fcd34d",fontSize:12}}>⬇️ PDF</button>
          </div>

          {/* Impression liste */}
          <button onClick={()=>setPrintList(true)} style={{...btn(),background:"#f0f9ff",color:"#0891b2",border:"1px solid #bae6fd",width:"100%",fontSize:12}}>
            🖨️ Imprimer liste d'inventaire
          </button>

          <PrintModal open={printList} onClose={()=>setPrintList(false)} title="Liste d'Inventaire">
            <div style={{marginBottom:12}}>
              <label style={{fontSize:13,fontWeight:600,color:"#374151",display:"flex",alignItems:"center",gap:6,cursor:"pointer"}}>
                <input type="checkbox" checked={showOldStock} onChange={e=>setShowOldStock(e.target.checked)}/>
                Afficher le stock système (ancien stock)
              </label>
            </div>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16,paddingBottom:12,borderBottom:"2px solid #0891b2"}}>
              <div style={{display:"flex",alignItems:"center",gap:10}}>
                <img src={LOGO_B64} alt="CHNCAK" style={{width:55,height:55,borderRadius:"50%",objectFit:"cover"}}/>
                <div>
                  <div style={{fontSize:13,fontWeight:800,color:"#0891b2"}}>CHNCAK</div>
                  <div style={{fontSize:9,color:"#64748b"}}>Centre Hospitalier National Cheikh Ahmadoul Khadim</div>
                  <div style={{fontSize:9,color:"#94a3b8"}}>PharmaStock</div>
                </div>
              </div>
              <div style={{textAlign:"right"}}>
                <div style={{fontWeight:800,fontSize:15,color:"#1e293b"}}>LISTE D'INVENTAIRE</div>
                <div style={{fontSize:11,color:"#64748b"}}>{monthLabel()} · {activeSupplier?.name}</div>
              </div>
            </div>
            <table style={{width:"100%",borderCollapse:"collapse",marginBottom:16}}>
              <thead>
                <tr>
                  <th style={thS}>Produit</th>
                  <th style={thS}>Unité</th>
                  {showOldStock&&<th style={thS}>Stock Sys.</th>}
                  {suppDepots.map(d=><th key={d.id} style={thS}>{d.name}</th>)}
                  <th style={thS}>Total</th>
                  <th style={thS}>Observations</th>
                </tr>
              </thead>
              <tbody>
                {suppProds.map(p=>(
                  <tr key={p.id}>
                    <td style={{...tdS,fontWeight:600}}>{p.name}</td>
                    <td style={tdS}>{p.unit}</td>
                    {showOldStock&&<td style={{...tdS,color:"#0891b2",fontWeight:700}}>{store.stock[p.id]||0}</td>}
                    {suppDepots.map(d=>{
                      const row=depotResults[d.id]?.find(r=>r.product.id===p.id);
                      return <td key={d.id} style={{...tdS,textAlign:"center"}}>{row?row.nw:"___"}</td>;
                    })}
                    <td style={{...tdS,fontWeight:700,color:"#0891b2",textAlign:"center"}}>
                      {result.find(r=>r.product.id===p.id)?.nw||"___"}
                    </td>
                    <td style={{...tdS,minWidth:100}}>___________</td>
                  </tr>
                ))}
              </tbody>
              <tfoot>
                <tr style={{background:"#f0f9ff"}}>
                  <td colSpan={showOldStock?2:1} style={{...tdS,fontWeight:700}}>TOTAL</td>
                  {showOldStock&&<td style={{...tdS,fontWeight:700,color:"#0891b2"}}>{suppProds.reduce((s,p)=>s+(store.stock[p.id]||0),0)}</td>}
                  {suppDepots.map(d=>{
                    const total=(depotResults[d.id]||[]).reduce((s,r)=>s+r.nw,0);
                    return <td key={d.id} style={{...tdS,fontWeight:700,textAlign:"center"}}>{total||"—"}</td>;
                  })}
                  <td style={{...tdS,fontWeight:800,color:"#0891b2",textAlign:"center"}}>{result.reduce((s,r)=>s+r.nw,0)}</td>
                  <td style={tdS}></td>
                </tr>
              </tfoot>
            </table>
            <div style={{display:"flex",justifyContent:"space-between",fontSize:11,color:"#94a3b8",borderTop:"1px solid #e2e8f0",paddingTop:10}}>
              <span>Signataire : ___________________________</span>
              <span>Date : {new Date().toLocaleDateString("fr-FR")}</span>
            </div>
          </PrintModal>
        </div>
      )}

      {step===4&&(
        <div style={{...card,textAlign:"center",padding:32}}>
          <div style={{fontSize:48,marginBottom:12}}>✅</div>
          <div style={{fontWeight:800,fontSize:18,color:"#059669",marginBottom:8}}>Inventaire validé !</div>
          <div style={{fontSize:13,color:"#64748b",marginBottom:4}}>{monthLabel()} · {activeSupplier?.name}</div>
          <div style={{fontSize:13,color:"#0891b2",marginBottom:20}}>{completedDepots.length} dépôt(s) · {result?.reduce((s,r)=>s+r.sold,0)} unités vendues</div>
          <div style={{display:"flex",gap:10,justifyContent:"center",flexWrap:"wrap"}}>
            <button onClick={createInvoice} style={{...btn(),background:"#7c3aed",color:"white"}}>🧾 Générer Facture</button>
            <button onClick={()=>{setStep(1);setResult(null);setDepotResults({});setDepotPhysical({});setDepotId("");}} style={{...btn(),background:"#f1f5f9",color:"#374151"}}>Nouvel Inventaire</button>
          </div>
        </div>
      )}
    </div>
  );
}



