function downloadInvoiceCSV(inv){
  const rows=(inv.items||[]).map(it=>[it.productName,it.qty,Number(it.unitPrice||0),Number(it.total||0)]);
  downloadCSV(inv.reference+".csv",rows,["Produit","Quantité","Prix unit. FCFA","Total FCFA"]);
}

function InvoicesPage({store,activeSupplier,onNav,currentUser}){
  const [sel,setSel]=useState(null);
  const [printing,setPrinting]=useState(false);
  const invoices=activeSupplier ? store.invoices.filter(i=>i.supplierId===activeSupplier.id) : store.invoices;

  if(sel){
    const inv=sel;
    return(
      <div style={{padding:16}}>
        <button onClick={()=>setSel(null)} style={{...btn(),background:"#f1f5f9",color:"#374151",marginBottom:16}}>← Retour</button>
        <div style={{...card}}>
          <div style={{display:"flex",justifyContent:"space-between",flexWrap:"wrap",gap:10,marginBottom:20}}>
            <div>
              <div style={{fontSize:20,fontWeight:800,color:"#0891b2"}}>FACTURE</div>
              <div style={{color:"#64748b",fontFamily:"monospace",fontSize:12}}>{inv.reference}</div>
            </div>
            <div style={{textAlign:"right"}}>
              <div style={{fontSize:12,color:"#64748b"}}>{inv.supplier} · {inv.month}</div>
              <div style={{fontSize:12,color:"#64748b"}}>{fmtDate(inv.date)}</div>
              {inv.createdByName&&<div style={{fontSize:11,color:"#94a3b8"}}>👤 Par {inv.createdByName}</div>}
              <Badge color={inv.status==="envoyée"?"#059669":inv.status==="payée"?"#7c3aed":"#f59e0b"}>{inv.status||"en attente"}</Badge>
            </div>
          </div>
          {(inv.items||[]).map((it,i)=>(
            <div key={i} style={{display:"flex",justifyContent:"space-between",padding:"9px 0",borderBottom:"1px solid #f1f5f9",fontSize:13}}>
              <div><div style={{fontWeight:600,color:"#1e293b"}}>{it.productName}</div><div style={{fontSize:11,color:"#64748b"}}>qté: {it.qty}</div></div>
              <div style={{fontWeight:700,color:"#0891b2"}}>{Number(it.total||0).toLocaleString("fr-FR")} FCFA</div>
            </div>
          ))}
          <div style={{background:"#f0f9ff",borderRadius:8,padding:12,display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:12}}>
            <span style={{fontWeight:700,color:"#1e293b"}}>TOTAL</span>
            <span style={{fontWeight:800,color:"#0891b2",fontSize:18}}>{Number(inv.total||0).toLocaleString("fr-FR")} FCFA</span>
          </div>
          {/* Boutons changement de statut */}
          <div style={{display:"flex",gap:6,marginTop:12,flexWrap:"wrap"}}>
            {(!inv.status||inv.status==="en attente")&&(
              <button onClick={()=>{store.updateInvoice(inv.id,{status:"envoyée"});setSel(prev=>({...prev,status:"envoyée"}));}}
                style={{background:"#dcfce7",color:"#059669",border:"1px solid #86efac",borderRadius:8,padding:"7px 14px",cursor:"pointer",fontWeight:600,fontSize:12}}>
                ✅ Marquer comme envoyée
              </button>
            )}
            {inv.status==="envoyée"&&(
              <button onClick={()=>{store.updateInvoice(inv.id,{status:"payée"});setSel(prev=>({...prev,status:"payée"}));}}
                style={{background:"#ede9fe",color:"#7c3aed",border:"1px solid #c4b5fd",borderRadius:8,padding:"7px 14px",cursor:"pointer",fontWeight:600,fontSize:12}}>
                💰 Marquer comme payée
              </button>
            )}
            {(inv.status==="envoyée"||inv.status==="payée")&&(
              <button onClick={()=>{store.updateInvoice(inv.id,{status:"en attente"});setSel(prev=>({...prev,status:"en attente"}));}}
                style={{background:"#fef3c7",color:"#d97706",border:"1px solid #fcd34d",borderRadius:8,padding:"7px 14px",cursor:"pointer",fontWeight:600,fontSize:12}}>
                ⏳ Remettre en attente
              </button>
            )}
          </div>
          <div style={{display:"flex",gap:8,marginTop:14,flexWrap:"wrap"}}>
            {/* Imprimer */}
            <button onClick={()=>setPrinting(true)} style={{...btn(),background:"#f8fafc",color:"#374151",border:"1px solid #e2e8f0"}}>🖨️</button>
            {/* Excel */}
            <button onClick={()=>{const rows=(inv.items||[]).map(it=>[it.productName,it.qty,Number(it.unitPrice||0),Number(it.total||0)]);downloadExcel(inv.reference+".xlsx",rows,["Produit","Qté","Prix unit. FCFA","Total FCFA"]);}} style={{...btn(),background:"#f0fdf4",color:"#059669",border:"1px solid #bbf7d0",fontSize:12}}>⬇️ Excel</button>
            {/* Télécharger PDF */}
            <button onClick={()=>{
              const tbl=""+pdfHeader("FACTURE",inv.reference)+
                "<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:14px;\">"+
                "<div style=\"background:#f8fafc;padding:8px 10px;border-radius:6px;\"><div style=\"font-size:9px;font-weight:700;color:#64748b;text-transform:uppercase;\">Fournisseur</div><div style=\"font-weight:600;\">"+inv.supplier+"</div></div>"+
                "<div style=\"background:#f8fafc;padding:8px 10px;border-radius:6px;\"><div style=\"font-size:9px;font-weight:700;color:#64748b;text-transform:uppercase;\">Période</div><div style=\"font-weight:600;\">"+inv.month+"</div></div></div>"+
                "<table><tr><th>Produit</th><th>Qté</th><th>Prix unit.</th><th>Total</th></tr>"+
                (inv.items||[]).map(it=>"<tr><td>"+it.productName+"</td><td>"+it.qty+"</td><td>"+Number(it.unitPrice||0).toLocaleString("fr-FR")+" FCFA</td><td>"+Number(it.total||0).toLocaleString("fr-FR")+" FCFA</td></tr>").join("")+
                "<tr class=\"total-row\"><td colspan=3>TOTAL</td><td>"+Number(inv.total||0).toLocaleString("fr-FR")+" FCFA</td></tr></table>"+
                "<div class=\"footer\">Généré le "+new Date().toLocaleDateString("fr-FR")+"</div>";
              downloadPDF("facture_"+inv.reference,tbl);
            }} style={{...btn(),background:"#fef3c7",color:"#92400e",border:"1px solid #fcd34d",fontSize:12}}>⬇️ PDF</button>
            {/* Envoyer par son propre mail */}
            <button onClick={()=>{
              const details=(inv.items||[]).map(it=>`- ${it.productName} | Qté: ${it.qty} | Prix unit.: ${Number(it.unitPrice||0).toLocaleString("fr-FR")} FCFA | Total: ${Number(it.total||0).toLocaleString("fr-FR")} FCFA`).join("\n");
              openMailClient({
                to: activeSupplier?.email || "",
                subject: `Facture ${inv.reference} — ${inv.month}`,
                body:
                  `Bonjour,\n\n`+
                  `Veuillez trouver ci-joint la facture ${inv.reference} pour la période ${inv.month}.\n\n`+
                  `Fournisseur : ${inv.supplier}\n`+
                  `Période     : ${inv.month}\n\n`+
                  `Détails :\n${details}\n\n`+
                  `TOTAL : ${Number(inv.total||0).toLocaleString("fr-FR")} FCFA\n\n`+
                  `Cordialement,\nCHNCAK PharmaStock`
              });
            }} style={{...btn(),background:"#0891b2",color:"white",flex:1}}>📧 Envoyer par mon mail</button>
          </div>
        </div>
        <PrintModal open={printing} onClose={()=>setPrinting(false)} title={"Facture " + (inv?.reference||"")}>
          <InvoicePrint inv={inv}/>
        </PrintModal>
      </div>
    );
  }

  const exportAllXLS=()=>{
    const rows=invoices.flatMap(inv=>(inv.items||[]).map(it=>[inv.reference,inv.month,inv.supplier,it.productName,it.qty,Number(it.unitPrice||0),Number(it.total||0),Number(inv.total||0)]));
    downloadExcel("factures_"+Date.now()+".xlsx",rows,["Référence","Période","Fournisseur","Produit","Qté","Prix unit. FCFA","Total ligne FCFA","Total facture FCFA"]);
  };

  return(
    <div style={{padding:16}}>
      <PageHeader pageId="factures" title="🧾 Factures"
        subtitle={activeSupplier?.name || "Tous fournisseurs"}>
        {invoices.length>0&&<button onClick={exportAllXLS} style={{...btn(),background:"rgba(255,255,255,0.15)",color:"white",border:"1px solid rgba(255,255,255,0.3)",fontSize:12}}>⬇️ Excel</button>}
      </PageHeader>
      {invoices.length===0
        ?<div style={{...card,textAlign:"center",padding:40}}><div style={{fontSize:40,marginBottom:10}}>📭</div><div style={{color:"#94a3b8"}}>Aucune facture. Effectuez un inventaire pour en générer.</div></div>
        :<div style={{display:"flex",flexDirection:"column",gap:10}}>
          {invoices.map(inv=>(
            <div key={inv.id} onClick={()=>setSel(inv)} style={{...card,cursor:"pointer",display:"flex",alignItems:"center",gap:14}}>
              <div style={{fontSize:28}}>🧾</div>
              <div style={{flex:1}}>
                <div style={{fontWeight:700,color:"#1e293b",fontSize:13}}>{inv.reference}</div>
                <div style={{fontSize:11,color:"#64748b"}}>{inv.supplier} · {inv.month}</div>
              </div>
              <div style={{textAlign:"right"}}>
                <div style={{fontWeight:800,color:"#0891b2",fontSize:15}}>{Number(inv.total||0).toLocaleString("fr-FR")} FCFA</div>
                <Badge color={inv.status==="envoyée"?"#059669":inv.status==="payée"?"#7c3aed":"#f59e0b"}>{inv.status||"en attente"}</Badge>
              </div>
            </div>
          ))}
        </div>
      }
    </div>
  );
}

// ─────────────────────────────────────────────
// INVENTORY HISTORY PAGE — avec détail cliquable
// ─────────────────────────────────────────────
function InventoryHistoryPage({store, activeSupplier, user}) {
  const [selected, setSelected] = useState(null);
  const [printing, setPrinting] = useState(false);
  const [deletingSelectedInv, setDeletingSelectedInv] = useState(false);

  const items = store.inventories.filter(i =>
    !activeSupplier || i.supplierId === activeSupplier?.id
  );

  const exportInvXLS = (inv) => {
    const rows = (inv.data||[]).map(r=>[
      r.product?.name||"", r.old||0, r.ent||0, r.ret||0, r.nw||0, r.sold||0
    ]);
    downloadExcel("inv_"+inv.month+".xlsx", rows,
      ["Produit","Stock Ancien","Entrées","Retours","Stock Nouveau","Vendus"]);
  };

  const exportAllXLS = () => {
    const rows = items.flatMap(inv=>(inv.data||[]).map(r=>[
      inv.month, fmtDate(inv.date), r.product?.name||"",
      r.old||0, r.ent||0, r.ret||0, r.nw||0, r.sold||0
    ]));
    downloadExcel("inventaires_"+Date.now()+".xlsx", rows,
      ["Mois","Date","Produit","Ancien","Entrées","Retours","Nouveau","Vendus"]);
  };

  const thS = {padding:"7px 8px",fontSize:11,fontWeight:700,color:"#64748b",
    background:"#f8fafc",borderBottom:"2px solid #e2e8f0",textAlign:"left"};
  const tdS = {padding:"7px 8px",borderBottom:"1px solid #f1f5f9",fontSize:12};

  // ── Vue détail d'un inventaire ──
  if (selected) {
    const inv = selected;
    const rows = inv.data || [];
    const totalVendus = rows.reduce((s,r)=>s+(r.sold||0),0);
    const totalNvStock = rows.reduce((s,r)=>s+(r.nw||0),0);

    return (
      <div style={{padding:0}}>
        <PageHeader pageId="hist-inv" title={"📋 Inventaire — " + inv.month}
          subtitle={fmtDate(inv.date) + (inv.createdByName ? " · 👤 " + inv.createdByName : "")}>
          <button onClick={()=>setPrinting(true)}
            style={{...btn(),background:"rgba(255,255,255,0.15)",color:"white",border:"1px solid rgba(255,255,255,0.3)",fontSize:12}}>🖨️</button>
          <button onClick={()=>exportInvXLS(inv)}
            style={{...btn(),background:"rgba(255,255,255,0.15)",color:"white",border:"1px solid rgba(255,255,255,0.3)",fontSize:12}}>⬇️ Excel</button>
          <button onClick={()=>setSelected(null)}
            style={{...btn(),background:"white",color:"#1e293b",fontWeight:700}}>← Retour</button>
        </PageHeader>

        {/* PrintModal */}
        <PrintModal open={printing} onClose={()=>setPrinting(false)}
          title={"Inventaire " + inv.month}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",
            marginBottom:16,paddingBottom:12,borderBottom:"2px solid #0891b2"}}>
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              <img src={LOGO_B64} alt="CHNCAK"
                style={{width:55,height:55,borderRadius:"50%",objectFit:"cover"}}/>
              <div>
                <div style={{fontSize:13,fontWeight:800,color:"#0891b2"}}>CHNCAK</div>
                <div style={{fontSize:9,color:"#64748b"}}>Centre Hospitalier National Cheikh Ahmadoul Khadim</div>
                <div style={{fontSize:9,color:"#94a3b8"}}>PharmaStock</div>
              </div>
            </div>
            <div style={{textAlign:"right"}}>
              <div style={{fontWeight:800,fontSize:16}}>RAPPORT D'INVENTAIRE</div>
              <div style={{fontSize:11,color:"#64748b"}}>{inv.month}</div>
              <div style={{fontSize:11,color:"#64748b"}}>{fmtDate(inv.date)}</div>
              {inv.createdByName&&<div style={{fontSize:10,color:"#94a3b8"}}>👤 {inv.createdByName}</div>}
            </div>
          </div>
          <table style={{width:"100%",borderCollapse:"collapse",marginBottom:14}}>
            <thead>
              <tr>
                {["Produit","Stock Anc.","Entrées","Retours","Stock Nouv.","Vendus"].map(h=>(
                  <th key={h} style={{...thS,border:"1px solid #e2e8f0"}}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {rows.map((r,i)=>(
                <tr key={i} style={{background:i%2===0?"white":"#f8fafc"}}>
                  <td style={{...tdS,border:"1px solid #e2e8f0",fontWeight:600}}>{r.product?.name||"—"}</td>
                  <td style={{...tdS,border:"1px solid #e2e8f0",textAlign:"center"}}>{r.old||0}</td>
                  <td style={{...tdS,border:"1px solid #e2e8f0",textAlign:"center",color:"#059669"}}>+{r.ent||0}</td>
                  <td style={{...tdS,border:"1px solid #e2e8f0",textAlign:"center",color:"#d97706"}}>-{r.ret||0}</td>
                  <td style={{...tdS,border:"1px solid #e2e8f0",textAlign:"center",color:"#0891b2",fontWeight:700}}>{r.nw||0}</td>
                  <td style={{...tdS,border:"1px solid #e2e8f0",textAlign:"center",
                    fontWeight:700,color:r.sold>0?"#059669":"#94a3b8"}}>{r.sold||0}</td>
                </tr>
              ))}
            </tbody>
            <tfoot>
              <tr style={{background:"#f0f9ff"}}>
                <td style={{...tdS,border:"1px solid #e2e8f0",fontWeight:800,color:"#0891b2"}}>TOTAL</td>
                <td colSpan={3} style={{...tdS,border:"1px solid #e2e8f0"}}></td>
                <td style={{...tdS,border:"1px solid #e2e8f0",textAlign:"center",fontWeight:800,color:"#0891b2"}}>{totalNvStock}</td>
                <td style={{...tdS,border:"1px solid #e2e8f0",textAlign:"center",fontWeight:800,color:"#059669"}}>{totalVendus}</td>
              </tr>
            </tfoot>
          </table>
          <div style={{fontSize:10,color:"#94a3b8",textAlign:"center",paddingTop:10,borderTop:"1px solid #e2e8f0"}}>
            Document généré par CHNCAK PharmaStock · {new Date().toLocaleDateString("fr-FR")}
          </div>
        </PrintModal>

        <div style={{padding:16}}>
          {/* Résumé */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(130px,1fr))",gap:10,marginBottom:16}}>
            {[
              {label:"Produits inventoriés", val:rows.length,       color:"#0891b2"},
              {label:"Total vendu",          val:totalVendus,       color:"#059669"},
              {label:"Stock nouveau total",  val:totalNvStock,      color:"#7c3aed"},
              {label:"Dépôts couverts",      val:Object.keys(inv.depotResults||{}).length, color:"#d97706"},
            ].map(k=>(
              <div key={k.label} style={{background:"white",borderRadius:10,padding:"12px 14px",
                boxShadow:"0 1px 4px rgba(0,0,0,0.07)",border:"1px solid #f1f5f9",textAlign:"center"}}>
                <div style={{fontSize:22,fontWeight:800,color:k.color}}>{k.val}</div>
                <div style={{fontSize:10,color:"#64748b",marginTop:3}}>{k.label}</div>
              </div>
            ))}
          </div>

          {/* Tableau détail */}
          <div style={{background:"white",borderRadius:12,overflow:"hidden",
            boxShadow:"0 1px 4px rgba(0,0,0,0.07)",border:"1px solid #f1f5f9",marginBottom:16}}>
            <div style={{padding:"12px 16px",background:"#f8fafc",borderBottom:"2px solid #e2e8f0",
              fontWeight:700,color:"#1e293b",fontSize:14}}>
              📊 Détail par produit
            </div>
            <div style={{overflowX:"auto"}}>
              <table style={{width:"100%",borderCollapse:"collapse"}}>
                <thead>
                  <tr>
                    {["Produit","Stock Ancien","+Entrées","−Retours","Stock Nouveau","VENDUS"].map(h=>(
                      <th key={h} style={thS}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {rows.length===0 && (
                    <tr><td colSpan={6} style={{...tdS,textAlign:"center",color:"#94a3b8",padding:24}}>Aucun détail disponible</td></tr>
                  )}
                  {rows.map((r,i)=>(
                    <tr key={i} style={{background:i%2===0?"white":"#fafafa"}}>
                      <td style={{...tdS,fontWeight:600,color:"#1e293b"}}>{r.product?.name||"—"}</td>
                      <td style={{...tdS,color:"#64748b",textAlign:"center"}}>{r.old||0}</td>
                      <td style={{...tdS,color:"#059669",fontWeight:600,textAlign:"center"}}>+{r.ent||0}</td>
                      <td style={{...tdS,color:"#d97706",fontWeight:600,textAlign:"center"}}>−{r.ret||0}</td>
                      <td style={{...tdS,color:"#0891b2",fontWeight:700,textAlign:"center"}}>{r.nw||0}</td>
                      <td style={{...tdS,textAlign:"center"}}>
                        <span style={{
                          background:r.sold>0?"#dcfce7":"#f1f5f9",
                          color:r.sold>0?"#059669":"#94a3b8",
                          padding:"3px 10px",borderRadius:99,fontWeight:700,fontSize:12
                        }}>{r.sold||0}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
                <tfoot>
                  <tr style={{background:"#f0f9ff"}}>
                    <td style={{...tdS,fontWeight:800,color:"#1e293b"}}>TOTAL</td>
                    <td colSpan={3} style={tdS}></td>
                    <td style={{...tdS,fontWeight:800,color:"#0891b2",textAlign:"center"}}>{totalNvStock}</td>
                    <td style={{...tdS,textAlign:"center"}}>
                      <span style={{background:"#0891b2",color:"white",padding:"3px 12px",
                        borderRadius:99,fontWeight:800,fontSize:13}}>{totalVendus}</span>
                    </td>
                  </tr>
                </tfoot>
              </table>
            </div>
          </div>

          {/* Détail par dépôt si disponible */}
          {Object.keys(inv.depotResults||{}).length > 1 && (
            <div style={{background:"white",borderRadius:12,padding:16,
              boxShadow:"0 1px 4px rgba(0,0,0,0.07)",border:"1px solid #f1f5f9"}}>
              <div style={{fontWeight:700,color:"#1e293b",fontSize:14,marginBottom:12}}>🏭 Par dépôt</div>
              {Object.entries(inv.depotResults||{}).map(([depotId, depotRows])=>{
                const d = store.depots.find(x=>x.id===depotId);
                const total = (depotRows||[]).reduce((s,r)=>s+(r.sold||0),0);
                return (
                  <div key={depotId} style={{marginBottom:10,padding:"10px 12px",
                    background:"#f8fafc",borderRadius:8}}>
                    <div style={{fontWeight:700,color:"#1e293b",fontSize:13,marginBottom:4}}>
                      🏭 {d?.name||depotId}
                      <span style={{marginLeft:8,fontSize:11,color:"#0891b2",fontWeight:400}}>
                        ({depotRows?.length||0} produits · Vendus : {total})
                      </span>
                    </div>
                    {(depotRows||[]).filter(r=>r.sold>0).map((r,i)=>(
                      <div key={i} style={{display:"flex",justifyContent:"space-between",
                        fontSize:12,padding:"3px 0",borderBottom:"1px solid #f1f5f9"}}>
                        <span style={{color:"#374151"}}>{r.product?.name||"—"}</span>
                        <span style={{color:"#059669",fontWeight:600}}>{r.sold} vendus (stock: {r.nw})</span>
                      </div>
                    ))}
                    {(depotRows||[]).every(r=>!r.sold)&&(
                      <div style={{fontSize:11,color:"#94a3b8"}}>Aucune vente dans ce dépôt</div>
                    )}
                  </div>
                );
              })}
            </div>
          )}

          {/* Actions bas de page */}
          {can(user,"hist-inv","d")&&(
            <div style={{display:"flex",gap:10,marginTop:14,flexWrap:"wrap"}}>
              <button onClick={()=>setDeletingSelectedInv(true)}
                style={{...btn(),background:"#fee2e2",color:"#ef4444",border:"1px solid #fca5a5"}}>
                🗑️ Supprimer cet inventaire
              </button>
              <ConfirmDelete open={deletingSelectedInv} onClose={()=>setDeletingSelectedInv(false)}
                label={inv.month}
                onConfirm={()=>store.deleteInventory(inv.id).then(()=>setSelected(null))}/>
            </div>
          )}
        </div>
      </div>
    );
  }

  // ── Vue liste ──
  return (
    <div style={{padding:0}}>
      <PageHeader pageId="hist-inv" title="📋 Historique Inventaires"
        subtitle={(items.length) + " inventaire(s)" + (activeSupplier?" · "+activeSupplier.name:"")}>
        {items.length>0&&(
          <button onClick={exportAllXLS}
            style={{...btn(),background:"rgba(255,255,255,0.15)",color:"white",
              border:"1px solid rgba(255,255,255,0.3)",fontSize:12}}>⬇️ Tout exporter</button>
        )}
      </PageHeader>
      <div style={{padding:16,display:"flex",flexDirection:"column",gap:10}}>
        {items.length===0&&(
          <div style={{...card,textAlign:"center",padding:40,color:"#94a3b8"}}>
            <div style={{fontSize:40,marginBottom:10}}>📭</div>
            Aucun inventaire enregistré.
          </div>
        )}
        {items.map(inv=>(
          <div key={inv.id} onClick={()=>setSelected(inv)}
            style={{...card,cursor:"pointer",transition:"box-shadow 0.2s",
              ":hover":{boxShadow:"0 4px 12px rgba(0,0,0,0.1)"}}}>
            <div style={{display:"flex",justifyContent:"space-between",
              flexWrap:"wrap",gap:8,alignItems:"center"}}>
              <div style={{flex:1}}>
                <div style={{fontWeight:700,color:"#1e293b",fontSize:14}}>{inv.month}</div>
                <div style={{fontSize:11,color:"#64748b",marginTop:2}}>
                  {fmtDate(inv.date)} · {inv.data?.length||0} produit(s)
                  {Object.keys(inv.depotResults||{}).length>0 &&
                    " · " + Object.keys(inv.depotResults).length + " dépôt(s)"}
                </div>
                {inv.createdByName&&(
                  <div style={{fontSize:10,color:"#94a3b8",marginTop:2}}>👤 {inv.createdByName}</div>
                )}
              </div>
              <div style={{display:"flex",alignItems:"center",gap:8}}>
                <div style={{textAlign:"right"}}>
                  <div style={{fontWeight:800,color:"#059669",fontSize:16}}>{inv.totalSold||0}</div>
                  <div style={{fontSize:10,color:"#64748b"}}>unités vendues</div>
                </div>
                <div style={{color:"#0891b2",fontSize:18}}>›</div>
              </div>
            </div>
            {/* Mini barre progression */}
            <div style={{marginTop:10,display:"flex",gap:6,flexWrap:"wrap"}}>
              {(inv.data||[]).filter(r=>r.sold>0).slice(0,4).map((r,i)=>(
                <span key={i} style={{background:"#f0fdf4",color:"#059669",
                  padding:"2px 8px",borderRadius:99,fontSize:10,fontWeight:600}}>
                  {r.product?.name?.split(" ")[0]||"—"} : {r.sold}
                </span>
              ))}
              {(inv.data||[]).filter(r=>r.sold>0).length>4&&(
                <span style={{background:"#f1f5f9",color:"#64748b",
                  padding:"2px 8px",borderRadius:99,fontSize:10}}>
                  +{(inv.data||[]).filter(r=>r.sold>0).length-4} autres
                </span>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// HISTORY
// ─────────────────────────────────────────────
function HistoryPage({title,icon,pageId,items,renderItem,empty,onExportCSV}){
  return(
    <div style={{padding:16}}>
      <PageHeader
        pageId={pageId}
        title={icon + " " + title}
        subtitle={items.length + " enregistrement(s)"}>
        {items.length>0&&onExportCSV&&(
          <button onClick={onExportCSV} style={{...btn(),background:"rgba(255,255,255,0.15)",color:"white",border:"1px solid rgba(255,255,255,0.3)",fontSize:12}}>
            ⬇️ Exporter
          </button>
        )}
      </PageHeader>
      {items.length===0
        ?<div style={{...card,textAlign:"center",padding:40}}><div style={{fontSize:40,marginBottom:10}}>📭</div><div style={{color:"#94a3b8"}}>{empty}</div></div>
        :<div style={{display:"flex",flexDirection:"column",gap:10}}>{items.map((it,i)=>renderItem(it,i))}</div>
      }
    </div>
  );
}

// ─────────────────────────────────────────────
// MESSAGING
// ─────────────────────────────────────────────
function MessagingPage({store,activeSupplier,pendingInvoiceId,onClearPending}){
  const [form,setForm]=useState({subject:"",body:"",attachInvoice:"",extraRecipients:""});
  const [sent,setSent]=useState(false);
  const [openMsg,setOpenMsg]=useState(null);
  const invoices=activeSupplier ? store.invoices.filter(i=>i.supplierId===activeSupplier.id) : store.invoices;
  const messages=activeSupplier ? store.messages.filter(m=>m.supplierId===activeSupplier.id) : store.messages;

  // Pré-remplir si on arrive depuis une facture
  useEffect(()=>{
    if(!pendingInvoiceId) return;
    const inv = store.invoices.find(i=>i.id===pendingInvoiceId);
    if(inv){
      setForm(f=>({
        ...f,
        attachInvoice: inv.id,
        subject: "Facture " + inv.reference + " — " + (inv.month||""),
        body: "Bonjour,\n\nVeuillez trouver ci-joint la facture " + inv.reference +
              " pour la période " + (inv.month||"") +
              " d'un montant de " + Number(inv.total||0).toLocaleString("fr-FR") + " FCFA.\n\nCordialement,\nCHNCAK",
      }));
    }
    onClearPending?.();
  },[pendingInvoiceId]);

  const [sending,  setSending]   = useState(false);
  const [sendError,setSendError] = useState("");

  const send = async () => {
    if(!activeSupplier){ alert("Sélectionnez un fournisseur actif."); return; }
    if(!form.subject.trim()){ alert("Veuillez saisir un objet."); return; }
    if(!form.body.trim()){    alert("Veuillez saisir un message."); return; }
    setSending(true); setSendError("");

    // Détails de la facture jointe (texte formaté pour l'email)
    let invoiceDetails = "";
    if(form.attachInvoice){
      const inv = store.invoices.find(i=>i.id===form.attachInvoice);
      if(inv){
        invoiceDetails = "=== FACTURE " + inv.reference + " ===\n"
          + "Période : " + inv.month + "\n"
          + "Fournisseur : " + inv.supplier + "\n"
          + "\nDétail :\n"
          + (inv.items||[]).map(it =>
              "  • " + it.productName + " × " + it.qty + "  →  "
              + Number(it.total||0).toLocaleString("fr-FR") + " FCFA"
            ).join("\n")
          + "\n\nTOTAL : " + Number(inv.total||0).toLocaleString("fr-FR") + " FCFA";
      }
    }

    // Vérifier si EmailJS est configuré
    const emailjsConfigured = EMAILJS_SERVICE_ID !== "VOTRE_SERVICE_ID"
      && EMAILJS_TEMPLATE_ID !== "VOTRE_TEMPLATE_ID"
      && EMAILJS_PUBLIC_KEY  !== "VOTRE_PUBLIC_KEY";

    if(emailjsConfigured){
      try {
        // Envoi au destinataire principal
        await sendRealEmail({
          to:               activeSupplier.email,
          toName:           activeSupplier.name,
          from:             "CHNCAK PharmaStock",
          subject:          form.subject,
          body:             form.body,
          invoiceDetails,
          extraRecipients:  form.extraRecipients,
        });
        // Envoi aux destinataires supplémentaires
        if(form.extraRecipients){
          const extras = form.extraRecipients.split(",").map(e=>e.trim()).filter(Boolean);
          for(const email of extras){
            await sendRealEmail({
              to: email, toName: email, from:"CHNCAK PharmaStock",
              subject: form.subject, body: form.body, invoiceDetails,
            });
          }
        }
        // Enregistrer dans Firebase
        store.addMessage({
          ...form, to:activeSupplier.name, toEmail:activeSupplier.email,
          supplierId:activeSupplier.id, from:"admin@pharma.com", emailSent:true,
        });
        // Marquer la facture comme "envoyée" dans Firestore
        if(form.attachInvoice){
          store.updateInvoice(form.attachInvoice, { status:"envoyée" });
        }
        setForm({subject:"",body:"",attachInvoice:"",extraRecipients:""});
        setSent(true); setTimeout(()=>setSent(false),5000);
      } catch(e){
        console.error("EmailJS error:", e);
        setSendError("❌ Erreur d'envoi : " + (e?.text || e?.message || "Vérifiez votre configuration EmailJS."));
      }
    } else {
      // EmailJS pas encore configuré — enregistrer seulement dans Firebase
      store.addMessage({
        ...form, to:activeSupplier.name, toEmail:activeSupplier.email,
        supplierId:activeSupplier.id, from:"admin@pharma.com", emailSent:false,
      });
      setForm({subject:"",body:"",attachInvoice:"",extraRecipients:""});
      setSendError("⚠️ Message enregistré mais EMAIL NON ENVOYÉ. Configurez EmailJS pour activer l'envoi réel (voir les instructions dans le code).");
      setTimeout(()=>setSendError(""),8000);
    }
    setSending(false);
  };

  const handleOpen=(m)=>{
    setOpenMsg(m.id===openMsg?null:m.id);
    if(!m.read) store.markRead(m.id);
  };

  return(
    <div style={{padding:16}}>
      <PageHeader pageId="messagerie" title="✉️ Messagerie" subtitle={activeSupplier?.name || "Sélectionnez un fournisseur"}/>
      {!activeSupplier&&<Alert type="warn">⚠️ Sélectionnez un fournisseur actif pour envoyer des messages.</Alert>}
      {sent&&<Alert type="success">✅ Email envoyé à {activeSupplier?.name} ({activeSupplier?.email}) !</Alert>}
      {sendError&&<Alert type={sendError.startsWith("⚠️")?"warn":"error"}>{sendError}</Alert>}
      {activeSupplier&&(
        <div style={{...card,marginBottom:14}}>
          <div style={{fontWeight:700,marginBottom:12,fontSize:14}}>Nouveau Message</div>
          <div style={{marginBottom:10}}>
            <label style={label}>Destinataire principal</label>
            <div style={{...input,background:"#f8fafc",color:"#1e293b",display:"flex",alignItems:"center",gap:6}}>
              🏢 {activeSupplier.name} ({activeSupplier.email})
            </div>
          </div>
          <div style={{marginBottom:10}}>
            <label style={label}>Destinataires supplémentaires <span style={{fontWeight:400,color:"#94a3b8"}}>(emails séparés par virgule)</span></label>
            <input style={input} value={form.extraRecipients} onChange={e=>setForm(f=>({...f,extraRecipients:e.target.value}))} placeholder="collegue@example.com, autre@example.com"/>
          </div>
          <div style={{marginBottom:10}}>
            <label style={label}>Objet</label>
            <input style={input} value={form.subject} onChange={e=>setForm(f=>({...f,subject:e.target.value}))} placeholder="Objet du message..."/>
          </div>
          <div style={{marginBottom:10}}>
            <label style={label}>Joindre une Facture</label>
            <select style={input} value={form.attachInvoice} onChange={e=>setForm(f=>({...f,attachInvoice:e.target.value}))}>
              <option value="">Aucune</option>
              {invoices.map(inv=><option key={inv.id} value={inv.id}>{inv.reference} — {inv.month} — {Number(inv.total||0).toLocaleString("fr-FR")} FCFA</option>)}
            </select>
          </div>
          <div style={{marginBottom:14}}>
            <label style={label}>Message</label>
            <textarea style={{...input,height:100,resize:"vertical"}} value={form.body} onChange={e=>setForm(f=>({...f,body:e.target.value}))} placeholder="Votre message..."/>
          </div>
          <button onClick={send} disabled={sending}
            style={{...btn(),background:sending?"#94a3b8":"#0891b2",color:"white",width:"100%",padding:11,fontSize:14}}>
            {sending?"⏳ Envoi en cours...":"📤 Envoyer le message"}
          </button>
        </div>
      )}
      <div style={{...card}}>
        <div style={{fontWeight:700,marginBottom:12,fontSize:14}}>Messages envoyés ({messages.length})</div>
        {messages.length===0
          ?<div style={{color:"#94a3b8",textAlign:"center",padding:20,fontSize:13}}>Aucun message</div>
          :messages.map(m=>(
            <div key={m.id} style={{borderRadius:8,marginBottom:8,border:"1px solid #f1f5f9",overflow:"hidden"}}>
              <div onClick={()=>handleOpen(m)} style={{background:m.read?"#f8fafc":"#eff6ff",padding:"10px 14px",cursor:"pointer",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <div>
                  <div style={{fontWeight:700,color:"#1e293b",fontSize:13,display:"flex",alignItems:"center",gap:8}}>
                    {!m.read&&<span style={{width:8,height:8,borderRadius:"50%",background:"#3b82f6",display:"inline-block"}}/>}
                    {m.subject||"(Sans objet)"}
                  </div>
                  <div style={{fontSize:11,color:"#64748b",display:"flex",alignItems:"center",gap:6,flexWrap:"wrap"}}>
                    <span>À : {m.to}{m.extraRecipients?` + ${m.extraRecipients.split(",").filter(x=>x.trim()).length} autre(s)`:""}</span>
                    <span>· {fmtDate(m.date)}</span>
                    {m.emailSent===true  && <span style={{background:"#dcfce7",color:"#059669",padding:"1px 6px",borderRadius:99,fontSize:10,fontWeight:700}}>✉️ Envoyé</span>}
                    {m.emailSent===false && <span style={{background:"#fef3c7",color:"#92400e",padding:"1px 6px",borderRadius:99,fontSize:10,fontWeight:700}}>📋 Enregistré</span>}
                  </div>
                </div>
                <span style={{fontSize:11,color:"#94a3b8"}}>{openMsg===m.id?"▲":"▼"}</span>
              </div>
              {openMsg===m.id&&(
                <div style={{background:"white",padding:"12px 14px",borderTop:"1px solid #f1f5f9"}}>
                  {m.createdByName&&<div style={{fontSize:11,color:"#64748b",marginBottom:6}}>👤 Envoyé par : <b>{m.createdByName}</b></div>}
                  {m.extraRecipients&&<div style={{fontSize:11,color:"#7c3aed",marginBottom:6}}>📧 Copie à : {m.extraRecipients}</div>}
                  <div style={{fontSize:13,color:"#374151",lineHeight:1.6,whiteSpace:"pre-wrap"}}>{m.body}</div>
                  {m.attachInvoice&&<div style={{fontSize:11,color:"#7c3aed",marginTop:8,padding:"6px 10px",background:"#fdf4ff",borderRadius:6}}>📎 Facture jointe : {store.invoices.find(i=>i.id===m.attachInvoice)?.reference||m.attachInvoice}</div>}
                </div>
              )}
            </div>
          ))
        }
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// PRODUCTS PAGE
// ─────────────────────────────────────────────
function ProductsPage({store,activeSupplier,currentUser}){
  const [showAdd,setShowAdd]=useState(false);
  const [editing,setEditing]=useState(null);
  const [form,setForm]=useState({name:"",price:"",unit:"Boîte",supplierId:""});
  const [printModal,setPrintModal]=useState(false);
  const [showOldStock,setShowOldStock]=useState(false);
  const [search,setSearch]=useState("");
  const [scanMsg,setScanMsg]=useState("");
  const [deletingProd,setDeletingProd]=useState(null);
  const scanProdRef=useRef(null);

  const products=activeSupplier ? store.products.filter(p=>p.supplierId===activeSupplier.id) : store.products;
  const filtered=search ? products.filter(p=>p.name.toLowerCase().includes(search.toLowerCase())) : products;
  const getSupplierName=id=>store.suppliers.find(s=>s.id===id)?.name||"—";

  const openAdd=()=>{
    setEditing(null);
    setForm({name:"",price:"",unit:"",supplierId:activeSupplier?.id||""});
    setShowAdd(true);
  };
  const openEdit=(p)=>{
    setEditing(p.id);
    setForm({name:p.name,price:String(p.price||""),unit:p.unit||"",supplierId:p.supplierId});
    setShowAdd(true);
  };
  const openDuplicate=(p)=>{
    setEditing(null);
    setForm({name:p.name,price:String(p.price||""),unit:p.unit||"",supplierId:activeSupplier?.id||p.supplierId});
    setShowAdd(true);
  };
  const save=()=>{
    const data={...form,price:Number(form.price)||0,unit:form.unit||"Boîte",supplierId:form.supplierId||activeSupplier?.id||""};
    if(editing) store.updateProduct(editing,data); else store.addProduct(data);
    setShowAdd(false);
  };

  const exportXLS=()=>{
    const rows=filtered.map(p=>[p.name,Number(p.price||0),p.unit,getSupplierName(p.supplierId),store.stock[p.id]||0]);
    downloadExcel("produits_"+Date.now()+".xlsx",rows,["Produit","Prix (FCFA)","Unité","Fournisseur","Stock"]);
  };

  const [scanReview,    setScanReview]    = useState(null); // résultat scan en attente de révision
  const [reviewOpen,    setReviewOpen]    = useState(false);

  const handleScanProducts=async(file)=>{
    if(!file) return;
    setScanMsg("⏳ Analyse du document...");
    try {
      const res=await scanDocumentWithAI(file, store.products);
      if(!res.success || !res.items || res.items.length===0){
        setScanMsg("⚠️ " + (res.error || "Aucun produit détecté. Vérifiez le fichier."));
        scanProdRef.current.value=""; return;
      }
      setScanMsg(""); // efface le message de chargement
      setScanReview(res);
      setReviewOpen(true); // ouvrir la modale de révision
    } catch(e) {
      setScanMsg("❌ Erreur : " + e.message);
    }
    scanProdRef.current.value="";
  };

  const handleConfirmImport = async (selectedRows) => {
    setReviewOpen(false);
    setScanMsg("⏳ Import en cours...");
    let added = 0;
    let skipped = 0;
    for (const row of selectedRows) {
      if (row.isNew) {
        // Nouveau produit → créer
        if (!row.productName?.trim()) continue;
        await store.addProduct({
          name:       row.productName.trim(),
          price:      Number(row.unitPrice||0),
          unit:       row.unit || "Boîte",
          supplierId: activeSupplier?.id || "",
        });
        added++;
      } else {
        skipped++; // produit existant sélectionné → on ne recrée pas
      }
    }
    const msgs = [];
    if (added > 0)   msgs.push("✅ " + added + " produit(s) ajouté(s)");
    if (skipped > 0) msgs.push("ℹ️ " + skipped + " produit(s) déjà dans la base (ignorés)");
    setScanMsg(msgs.join(" · ") || "ℹ️ Aucun nouveau produit ajouté.");
    setScanReview(null);
  };

  const thS={padding:"8px 10px",textAlign:"left",fontSize:11,fontWeight:700,color:"#64748b",borderBottom:"2px solid #e2e8f0",background:"#f8fafc"};
  const tdS={padding:"8px 10px",borderBottom:"1px solid #f1f5f9",fontSize:13};

  return(
    <div style={{padding:16}}>
      <PageHeader pageId="produits" title="💊 Produits"
        subtitle={activeSupplier?.name || "Tous fournisseurs"}>
        <button onClick={()=>setPrintModal(true)} style={{...btn(),background:"rgba(255,255,255,0.15)",color:"white",border:"1px solid rgba(255,255,255,0.3)",fontSize:11}}>🖨️</button>
        <button onClick={exportXLS} style={{...btn(),background:"rgba(255,255,255,0.15)",color:"white",border:"1px solid rgba(255,255,255,0.3)",fontSize:11}}>⬇️ Excel</button>
        <button onClick={()=>{setScanMsg("");scanProdRef.current?.click();}} style={{...btn(),background:"rgba(255,255,255,0.2)",color:"white",fontSize:11}}>📄 Importer</button>
        {can(currentUser,"produits","w")&&<button onClick={openAdd} style={{...btn(),background:"white",color:"#059669",fontWeight:700}}>+ Nouveau</button>}
        <input ref={scanProdRef} type="file" accept=".xlsx,.pdf,.jpg,.png" style={{display:"none"}} onChange={e=>{if(e.target.files[0])handleScanProducts(e.target.files[0]);e.target.value="";}}/>
      </PageHeader>

      {!activeSupplier&&<Alert type="warn">Affichage de tous les produits. Sélectionnez un fournisseur pour filtrer.</Alert>}
      {scanMsg&&<Alert type={scanMsg.startsWith("✅")?"success":scanMsg.startsWith("⚠️")||scanMsg.startsWith("ℹ️")?"warn":"error"}>{scanMsg}</Alert>}

      <input style={{...input,marginBottom:12}} placeholder="🔍 Rechercher un produit..." value={search} onChange={e=>setSearch(e.target.value)}/>

      {/* Modal ajout/modif */}
      <Modal open={showAdd} onClose={()=>setShowAdd(false)} title={editing?"✏️ Modifier Produit":"💊 Nouveau Produit"}>
        <div style={{marginBottom:12}}>
          <label style={label}>Nom du produit</label>
          <input style={input} list="products-suggestions" value={form.name}
            onChange={e=>setForm(f=>({...f,name:e.target.value}))}
            placeholder="Saisir le nom complet du produit ou consommable"/>
          <datalist id="products-suggestions">
            {/* Médicaments courants */}
            {["Amoxicilline 500mg","Amoxicilline 1g","Ampicilline 500mg","Paracétamol 500mg",
              "Paracétamol 1g","Ibuprofène 400mg","Ibuprofène 200mg","Aspirine 500mg",
              "Métronidazole 250mg","Métronidazole 500mg","Cotrimoxazole 480mg",
              "Cotrimoxazole 960mg","Amoxicilline + Acide clavulanique 1g",
              "Ciprofloxacine 500mg","Doxycycline 100mg","Érythromycine 500mg",
              "Cloxacilline 500mg","Céfixime 200mg","Céfuroxime 500mg",
              "Oméprazole 20mg","Oméprazole 40mg","Ranitidine 150mg",
              "Metformine 500mg","Metformine 850mg","Metformine 1000mg",
              "Glibenclamide 5mg","Lisinopril 5mg","Lisinopril 10mg",
              "Amlodipine 5mg","Amlodipine 10mg","Atorvastatine 20mg",
              "Atorvastatine 40mg","Simvastatine 20mg","Losartan 50mg",
              "Furosémide 40mg","Spironolactone 25mg","Prednisolone 5mg",
              "Dexaméthasone 0.5mg","Prednisolone 20mg",
              "Salbutamol 4mg","Salbutamol spray","Béclométasone spray",
              "Diazépam 5mg","Phénobarbital 50mg","Carbamazépine 200mg",
              "Chloroquine 100mg","Arthémether + Luméfantrine","Quinine 300mg",
              "Artésunate injectable","Artéméther injectable",
              "Sérum glucosé 5%","Sérum glucosé 10%","Sérum physiologique 0.9%",
              "Ringer Lactate","Eau pour injection","Sang total",
              "Vitamine C 500mg","Vitamine B complexe","Fer + Acide folique",
              "Multivitamines","Calcium 500mg",
              /* Consommables */
              "Gants d'examen (paire)","Gants chirurgicaux stériles",
              "Seringue 2ml","Seringue 5ml","Seringue 10ml","Seringue 20ml",
              "Perfuseur","Cathéter IV 18G","Cathéter IV 20G","Cathéter IV 22G",
              "Compresse stérile 10x10","Compresse non stérile",
              "Bande de gaze","Bande élastique","Sparadrap","Pansement adhésif",
              "Coton hydrophile","Alcool 70°","Eau oxygénée 10 volumes",
              "Iode polyvidone solution","Iode polyvidone mousse",
              "Masque chirurgical","Masque FFP2","Lunettes de protection",
              "Tablier plastique","Sur-chaussures","Bonnet de bloc",
              "Lame de bistouri","Fil de suture résorbable","Fil de suture non résorbable",
              "Aiguille à suture","Trocart","Drain de Redon",
              "Sonde urinaire","Sonde nasogastrique","Sonde d'aspiration",
              "Thermomètre","Tensiomètre","Oxymètre de pouls",
              "Bandelette urinaire","Bandelette glycémique",
              "Test rapide paludisme","Test rapide grossesse","Test rapide VIH",
              "Lame porte-objet","Lamelle couvre-objet","Tube EDTA",
              "Tube sec","Tube hépariné","Boîte à aiguilles",
              "Sac poubelle rouge","Sac poubelle jaune","Container sharps"].map(s=>(
              <option key={s} value={s}/>
            ))}
            {/* Suggestions depuis les produits existants */}
            {store.products.filter(p=>p.name&&!["Amoxicilline 500mg"].includes(p.name)).map(p=>(
              <option key={p.id} value={p.name}/>
            ))}
          </datalist>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:12}}>
          <div>
            <label style={label}>Prix (FCFA)</label>
            <input style={input} type="number" min="0" value={form.price}
              onChange={e=>setForm(f=>({...f,price:e.target.value}))} placeholder="1200"/>
          </div>
          <div>
            <label style={label}>Unité <span style={{fontWeight:400,color:"#94a3b8",fontSize:10}}>(ou saisir)</span></label>
            <input style={input} list="units-list" value={form.unit||""}
              onChange={e=>setForm(f=>({...f,unit:e.target.value}))}
              placeholder="Boîte, Flacon, Pièce..."/>
            <datalist id="units-list">
              {["Boîte","Flacon","Ampoule","Sachet","Comprimé","Tube","Plaquette",
                "Pièce","Rouleau","Paquet","Litre","ml","Paire","Kit","Carton"].map(u=>(
                <option key={u} value={u}/>
              ))}
            </datalist>
          </div>
        </div>
        <div style={{marginBottom:16}}>
          <label style={label}>Fournisseur</label>
          <select style={input} value={form.supplierId} onChange={e=>setForm(f=>({...f,supplierId:e.target.value}))}>
            <option value="">— Sélectionner —</option>
            {store.suppliers.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
          </select>
          {!form.supplierId&&activeSupplier&&<div style={{fontSize:11,color:"#0891b2",marginTop:4}}>Par défaut : {activeSupplier.name}</div>}
        </div>
        <button onClick={save} disabled={!form.name||!(form.supplierId||activeSupplier?.id)}
          style={{...btn(),background:"#0891b2",color:"white",width:"100%",padding:11}}>
          {editing?"✏️ Enregistrer modifications":"💾 Enregistrer"}
        </button>
      </Modal>

      {/* Liste inventaire imprimable */}
      <PrintModal open={printModal} onClose={()=>setPrintModal(false)} title="Liste d'Inventaire">
        <div style={{marginBottom:12}}>
          <label style={{fontSize:13,fontWeight:600,color:"#374151",display:"flex",alignItems:"center",gap:6,cursor:"pointer"}}>
            <input type="checkbox" checked={showOldStock} onChange={e=>setShowOldStock(e.target.checked)}/>
            Afficher l'ancien stock (stock système)
          </label>
        </div>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16,paddingBottom:12,borderBottom:"2px solid #0891b2"}}>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <img src={LOGO_B64} alt="CHNCAK" style={{width:55,height:55,borderRadius:"50%",objectFit:"cover"}}/>
            <div>
              <div style={{fontSize:13,fontWeight:800,color:"#0891b2"}}>CHNCAK</div>
              <div style={{fontSize:9,color:"#64748b"}}>Centre Hospitalier National Cheikh Ahmadoul Khadim</div>
              <div style={{fontSize:9,color:"#94a3b8"}}>PharmaStock</div>
            </div>
          </div>
          <div style={{textAlign:"right"}}>
            <div style={{fontWeight:800,fontSize:16,color:"#1e293b"}}>LISTE DES PRODUITS</div>
            <div style={{fontSize:12,color:"#64748b"}}>{monthLabel()} · {activeSupplier?.name||"Tous fournisseurs"}</div>
          </div>
        </div>
        <table style={{width:"100%",borderCollapse:"collapse"}}>
          <thead>
            <tr>
              <th style={thS}>Produit</th>
              <th style={thS}>Unité</th>
              <th style={thS}>Prix FCFA</th>
              {showOldStock&&<th style={thS}>Stock Système</th>}
              <th style={thS}>Stock Physique</th>
              <th style={thS}>Observations</th>
            </tr>
          </thead>
          <tbody>
            {filtered.map(p=>(
              <tr key={p.id}>
                <td style={{...tdS,fontWeight:600}}>{p.name}</td>
                <td style={tdS}>{p.unit}</td>
                <td style={tdS}>{Number(p.price||0).toLocaleString("fr-FR")}</td>
                {showOldStock&&<td style={{...tdS,color:"#0891b2",fontWeight:700}}>{store.stock[p.id]||0}</td>}
                <td style={{...tdS,minWidth:80}}>___________</td>
                <td style={{...tdS,minWidth:120}}>___________</td>
              </tr>
            ))}
          </tbody>
        </table>
        <div style={{marginTop:16,display:"flex",justifyContent:"space-between",fontSize:11,color:"#94a3b8",borderTop:"1px solid #e2e8f0",paddingTop:10}}>
          <span>Signataire : ___________________________</span>
          <span>Date : {new Date().toLocaleDateString("fr-FR")}</span>
        </div>
      </PrintModal>

      {/* Modale de révision scan produits */}
      <ScanReviewModal
        open={reviewOpen}
        onClose={()=>{setReviewOpen(false);setScanReview(null);}}
        scanResult={scanReview}
        allProducts={store.products}
        activeSupplier={activeSupplier}
        onConfirm={handleConfirmImport}
        mode="products"
      />

      {/* Liste produits */}
      {/* ConfirmDelete pour produits */}
      <ConfirmDelete open={!!deletingProd} onClose={()=>setDeletingProd(null)}
        label={deletingProd?.name||""}
        onConfirm={()=>store.deleteProduct(deletingProd.id)}/>

      <div style={{display:"flex",flexDirection:"column",gap:8}}>
        {filtered.map(p=>{
          const qty=store.stock[p.id]||0;
          return(
            <div key={p.id} style={{...card,padding:14}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:8}}>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontWeight:700,color:"#1e293b",fontSize:13}}>{p.name}</div>
                  <div style={{fontSize:11,color:"#64748b",marginTop:2}}>{p.unit||"Boîte"} · {Number(p.price||0).toLocaleString("fr-FR")} FCFA</div>
                  <div style={{fontSize:11,color:"#94a3b8"}}>{getSupplierName(p.supplierId)}</div>
                  {p.createdByName&&<div style={{fontSize:10,color:"#cbd5e1"}}>👤 {p.createdByName}</div>}
                </div>
                <div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:5,flexShrink:0}}>
                  <div style={{fontWeight:800,color:qty<30?"#ef4444":"#059669",fontSize:16}}>{qty}</div>
                  <Badge color={qty<30?"#ef4444":"#059669"}>{qty<30?"Stock bas":"OK"}</Badge>
                  <div style={{display:"flex",gap:4,flexWrap:"wrap",justifyContent:"flex-end"}}>
                    {can(currentUser,"produits","w")&&<button onClick={()=>openEdit(p)} style={{...btn(),background:"#f0f9ff",color:"#0891b2",padding:"4px 8px",fontSize:11}}>✏️</button>}
                    {can(currentUser,"produits","w")&&<button onClick={()=>openDuplicate(p)} title="Dupliquer" style={{...btn(),background:"#fdf4ff",color:"#7c3aed",padding:"4px 8px",fontSize:11}}>⧉</button>}
                    {can(currentUser,"produits","d")&&<button onClick={()=>setDeletingProd(p)} style={{...btn(),background:"#fee2e2",color:"#ef4444",padding:"4px 8px",fontSize:11}}>🗑️</button>}
                  </div>
                </div>
              </div>
            </div>
          );
        })}
        {filtered.length===0&&<div style={{...card,textAlign:"center",padding:40,color:"#94a3b8"}}>Aucun produit trouvé.</div>}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// DEPOTS PAGE
// ─────────────────────────────────────────────
function DepotsPage({store,activeSupplier,currentUser}){
  const [show,setShow]=useState(false);
  const [editing,setEditing]=useState(null);
  const [form,setForm]=useState({name:"",location:"",supplierId:"",isPrincipal:false});
  const [deletingDepot,setDeletingDepot]=useState(null);
  const depots=(activeSupplier ? store.depots.filter(d=>d.supplierId===activeSupplier.id) : store.depots).filter(d=>!d.isPrincipal && !d.isAutoCreated);
  const getSupplierName=id=>store.suppliers.find(s=>s.id===id)?.name||"—";

  const open=(d=null)=>{
    setEditing(d?.id||null);
    if(d){
      setForm({name:d.name||"",location:d.location||"",supplierId:d.supplierId||activeSupplier?.id||"",isPrincipal:d.isPrincipal||false});
    } else {
      setForm({name:"",location:"",supplierId:activeSupplier?.id||"",isPrincipal:false});
    }
    setShow(true);
  };

  const save=()=>{
    const suppId = form.supplierId || activeSupplier?.id || "";
    if(!form.name.trim()||!form.location.trim()||!suppId){
      alert("Veuillez remplir le nom, la localisation et sélectionner un fournisseur.");
      return;
    }
    const data = { name:form.name.trim(), location:form.location.trim(), supplierId:suppId, isPrincipal:form.isPrincipal };
    // Si on marque comme principal, retirer le flag des autres dépôts du même fournisseur
    if(form.isPrincipal){
      store.depots.filter(d=>d.supplierId===suppId && d.id!==(editing||"")).forEach(d=>{
        if(d.isPrincipal) store.updateDepot(d.id,{...d,isPrincipal:false});
      });
    }
    if(editing) store.updateDepot(editing,data); else store.addDepot(data);
    setShow(false);
    setForm({name:"",location:"",supplierId:activeSupplier?.id||"",isPrincipal:false});
  };

  const setPrincipal=(d)=>{
    const suppId=d.supplierId;
    // Retirer principal des autres
    store.depots.filter(dep=>dep.supplierId===suppId).forEach(dep=>{
      store.updateDepot(dep.id,{...dep,isPrincipal:dep.id===d.id});
    });
  };

  const suppProdsCount=activeSupplier?store.products.filter(p=>p.supplierId===activeSupplier.id).length:0;

  return(
    <div style={{padding:16}}>
      <ConfirmDelete open={!!deletingDepot} onClose={()=>setDeletingDepot(null)}
        label={deletingDepot?.name||""} onConfirm={()=>store.deleteDepot(deletingDepot.id)}/>
      <PageHeader pageId="depots" title="🏭 Dépôts"
        subtitle={activeSupplier ? "Chaque dépôt contient tous les " + suppProdsCount + " produit(s) de " + activeSupplier.name : "Tous fournisseurs"}>
        {can(currentUser,"depots","w")&&<button onClick={()=>open()} style={{...btn(),background:"white",color:"#1c1917",fontWeight:700}}>+ Nouveau</button>}
      </PageHeader>

      <Modal open={show} onClose={()=>setShow(false)} title={editing?"✏️ Modifier Dépôt":"🏭 Nouveau Dépôt"}>
        <div style={{marginBottom:12}}>
          <label style={label}>Nom du dépôt</label>
          <input style={input} value={form.name}
            onChange={e=>setForm(f=>({...f,name:e.target.value}))}
            placeholder="Ex: Dépôt A — Bâtiment Nord"/>
        </div>
        <div style={{marginBottom:12}}>
          <label style={label}>Localisation / Description</label>
          <input style={input} value={form.location}
            onChange={e=>setForm(f=>({...f,location:e.target.value}))}
            placeholder="Ex: Rez-de-chaussée, salle 12"/>
        </div>
        <div style={{marginBottom:12}}>
          <label style={label}>Fournisseur associé</label>
          {activeSupplier && !editing ? (
            <div style={{...input,background:"#f0f9ff",color:"#0891b2",fontWeight:600,display:"flex",alignItems:"center",gap:6}}>
              🏢 {activeSupplier.name}
              <span style={{fontSize:10,color:"#64748b",fontWeight:400,marginLeft:4}}>(fournisseur actif)</span>
            </div>
          ) : (
            <select style={input} value={form.supplierId}
              onChange={e=>setForm(f=>({...f,supplierId:e.target.value}))}>
              <option value="">— Sélectionner un fournisseur —</option>
              {store.suppliers.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
            </select>
          )}
          {store.suppliers.length===0&&(
            <div style={{fontSize:11,color:"#f59e0b",marginTop:4}}>
              ⚠️ Aucun fournisseur. Créez d'abord un fournisseur dans la section Fournisseurs.
            </div>
          )}
        </div>
        {/* Dépôt principal */}
        <div style={{marginBottom:16,background:"#f0f9ff",borderRadius:8,padding:"10px 12px",border:"1px solid #bae6fd"}}>
          <label style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer"}}>
            <input type="checkbox" checked={form.isPrincipal}
              onChange={e=>setForm(f=>({...f,isPrincipal:e.target.checked}))}
              style={{width:16,height:16,cursor:"pointer"}}/>
            <div>
              <div style={{fontWeight:700,fontSize:12,color:"#0c4a6e"}}>⭐ Dépôt principal</div>
              <div style={{fontSize:11,color:"#64748b"}}>Le stock global du fournisseur sera mis à jour depuis ce dépôt après inventaire</div>
            </div>
          </label>
        </div>
        <button onClick={save}
          disabled={!form.name.trim()||!form.location.trim()||(!form.supplierId&&!activeSupplier?.id)}
          style={{...btn(),background:(!form.name.trim()||!form.location.trim()||(!form.supplierId&&!activeSupplier?.id))?"#cbd5e1":"#0891b2",color:"white",width:"100%",padding:11}}>
          {editing?"✏️ Enregistrer les modifications":"🏭 Créer le Dépôt"}
        </button>
      </Modal>

      <div style={{display:"flex",flexDirection:"column",gap:8}}>
        {depots.map(d=>{
          const totalQty=store.products.filter(p=>p.supplierId===d.supplierId).reduce((s,p)=>s+(store.stock[p.id]||0),0);
          return(
            <div key={d.id} style={{...card,padding:16,border:d.isPrincipal?"2px solid #0891b2":"1.5px solid #f1f5f9"}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:8}}>
                <div style={{flex:1}}>
                  <div style={{display:"flex",alignItems:"center",gap:6}}>
                    <div style={{fontWeight:700,color:"#1e293b",fontSize:14}}>🏭 {d.name}</div>
                    {d.isPrincipal&&<span style={{background:"#0891b2",color:"white",fontSize:10,fontWeight:700,borderRadius:99,padding:"2px 8px"}}>⭐ Principal</span>}
                  </div>
                  <div style={{fontSize:12,color:"#64748b",marginTop:2}}>{d.location}</div>
                  <div style={{fontSize:11,color:"#94a3b8"}}>Fournisseur : {getSupplierName(d.supplierId)}</div>
                  <div style={{fontSize:11,color:"#0891b2",marginTop:4}}>
                    {store.products.filter(p=>p.supplierId===d.supplierId).length} produits · stock : {totalQty}
                  </div>
                </div>
                <div style={{display:"flex",gap:5,flexShrink:0,flexWrap:"wrap",justifyContent:"flex-end"}}>
                  {can(currentUser,"depots","w")&&!d.isPrincipal&&(
                    <button onClick={()=>setPrincipal(d)}
                      style={{...btn(),background:"#f0f9ff",color:"#0891b2",padding:"5px 8px",fontSize:11}}>⭐ Principal</button>
                  )}
                  {can(currentUser,"depots","w")&&<button onClick={()=>open(d)} style={{...btn(),background:"#f0f9ff",color:"#0891b2",padding:"5px 8px",fontSize:11}}>✏️</button>}
                  {can(currentUser,"depots","d")&&<button onClick={()=>setDeletingDepot(d)} style={{...btn(),background:"#fee2e2",color:"#ef4444",padding:"5px 8px",fontSize:11}}>🗑️</button>}
                </div>
              </div>
            </div>
          );
        })}
        {depots.length===0&&<div style={{...card,textAlign:"center",padding:40,color:"#94a3b8"}}>Aucun dépôt. Créez votre premier dépôt.</div>}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// FOURNISSEURS PAGE
// ─────────────────────────────────────────────
function FournisseursPage({store,activeSupplier,onActivate,currentUser}){
  const [show,setShow]=useState(false);
  const [editing,setEditing]=useState(null);
  const [form,setForm]=useState({name:"",email:"",phone:"",address:""});
  const [deletingFour,setDeletingFour]=useState(null);

  const open=(s=null)=>{
    setEditing(s?.id||null);
    setForm(s?{name:s.name,email:s.email,phone:s.phone,address:s.address}:{name:"",email:"",phone:"",address:""});
    setShow(true);
  };
  const save=async()=>{
    if(editing){
      store.updateSupplier(editing,form);
    } else {
      // Créer le fournisseur et son dépôt principal automatiquement
      const ref = await store.addSupplier(form);
      const supplierId = ref?.id;
      if(supplierId){
        await store.addDepot({
          name: "Dépôt principal — " + form.name,
          location: "Dépôt principal",
          supplierId,
          isPrincipal: true,
          isAutoCreated: true, // marqueur pour ne pas afficher dans la liste
        });
      }
    }
    setShow(false);
  };

  return(
    <div style={{padding:16}}>
      <ConfirmDelete open={!!deletingFour} onClose={()=>setDeletingFour(null)}
        label={deletingFour?.name||""} onConfirm={()=>store.deleteSupplier(deletingFour.id)}/>
      <PageHeader pageId="fournisseurs" title="🏢 Fournisseurs" subtitle="Gestion des fournisseurs">
        {can(currentUser,"fournisseurs","w")&&<button onClick={()=>open()} style={{...btn(),background:"white",color:"#0f172a",fontWeight:700}}>+ Nouveau</button>}
      </PageHeader>

      <Modal open={show} onClose={()=>setShow(false)} title={editing?"✏️ Modifier Fournisseur":"🏢 Nouveau Fournisseur"}>
        {[["Nom","name","Ex: PharmaCorp"],["Email","email","contact@..."],["Téléphone","phone","01 23..."],["Adresse","address","12 rue..."]].map(([lb,field,ph])=>(
          <div key={field} style={{marginBottom:12}}><label style={label}>{lb}</label><input style={input} value={form[field]||""} onChange={e=>setForm(f=>({...f,[field]:e.target.value}))} placeholder={ph}/></div>
        ))}
        <button onClick={save} disabled={!form.name||!form.email} style={{...btn(),background:"#0891b2",color:"white",width:"100%",padding:11}}>
          {editing?"✏️ Modifier":"💾 Enregistrer"}
        </button>
      </Modal>

      <div style={{display:"flex",flexDirection:"column",gap:8}}>
        {store.suppliers.map(s=>{
          const isActive=activeSupplier?.id===s.id;
          const depots=store.depots.filter(d=>d.supplierId===s.id);
          const prods=store.products.filter(p=>p.supplierId===s.id);
          return(
            <div key={s.id} style={{...card,padding:16,border:isActive?"2px solid #0891b2":"1.5px solid #f1f5f9",background:isActive?"#f0f9ff":"white"}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:8}}>
                <div>
                  <div style={{fontWeight:700,color:"#1e293b",fontSize:14}}>🏢 {s.name}</div>
                  {isActive&&<Badge color="#0891b2">✓ Actif</Badge>}
                </div>
                <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
                  {can(currentUser,"fournisseurs","w")&&<button onClick={()=>open(s)} style={{...btn(),background:"#f0f9ff",color:"#0891b2",padding:"5px 8px",fontSize:11}}>✏️</button>}
                  <button onClick={()=>onActivate(s)} style={{...btn(),background:isActive?"#dcfce7":"#0891b2",color:isActive?"#059669":"white",padding:"5px 8px",fontSize:11}}>
                    {isActive?"✓ Actif":"Activer"}
                  </button>
                  {can(currentUser,"fournisseurs","d")&&!isActive&&<button onClick={()=>setDeletingFour(s)} style={{...btn(),background:"#fee2e2",color:"#ef4444",padding:"5px 8px",fontSize:11}}>🗑️</button>}
                </div>
              </div>
              <div style={{fontSize:12,color:"#64748b"}}>{s.email}</div>
              <div style={{fontSize:12,color:"#64748b"}}>{s.phone} · {s.address}</div>
              <div style={{fontSize:11,color:"#94a3b8",marginTop:6}}>{depots.length} dépôt(s) · {prods.length} produit(s)</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// USERS PAGE
// ─────────────────────────────────────────────
function UsersPage({store, currentUser}){
  const [show,       setShow]       = useState(false);
  const [editing,    setEditing]    = useState(null);
  const [permTab,    setPermTab]    = useState(null);  // user dont on édite les permissions
  const [deletingU,  setDeletingU]  = useState(null);
  const [resetPwU,   setResetPwU]   = useState(null);  // user dont on reset le mdp
  const [newPw,      setNewPw]      = useState("");
  const [pwMsg,      setPwMsg]      = useState("");
  const [form,       setForm]       = useState({name:"",email:"",role:"magasinier",tempPw:""});
  const [showTempPw, setShowTempPw] = useState(false);
  const [permForm,   setPermForm]   = useState({});
  const [showPwReset,setShowPwReset]= useState(false);

  const openAdd = () => {
    setEditing(null);
    setForm({name:"",email:"",role:"magasinier",tempPw:""});
    setShowTempPw(false);
    setShow(true);
  };
  const openEdit = (u) => {
    setEditing(u.id);
    setForm({name:u.name,email:u.email,role:u.role});
    setShow(true);
  };
  const save = async () => {
    if(editing) await store.updateUser(editing, form);
    else await store.addUser(form);
    setShow(false);
  };

  const openPerms = (u) => {
    const base = DEFAULT_PERMS[u.role] || {};
    setPermForm(u.permissions ? {...base,...u.permissions} : {...base});
    setPermTab(u);
  };
  const savePerms = async () => {
    await store.updateUser(permTab.id, {permissions: permForm});
    setPermTab(null);
  };
  const togglePerm = (sectionId, right) => {
    setPermForm(prev => ({
      ...prev,
      [sectionId]: { ...(prev[sectionId]||{}), [right]: prev[sectionId]?.[right] ? 0 : 1 }
    }));
  };

  const handleResetPassword = async () => {
    if(!newPw || newPw.length < 6) { setPwMsg("⚠️ Minimum 6 caractères."); return; }
    try {
      // Stocker le mot de passe provisoire dans Firestore (l'user devra le changer)
      await store.updateUser(resetPwU.id, { provisionalPw: newPw, mustChangePw: true });
      setPwMsg("✅ Mot de passe provisoire défini. L'utilisateur verra le nouveau mot de passe à sa prochaine connexion.");
      setTimeout(()=>{ setResetPwU(null); setPwMsg(""); setNewPw(""); setShowPwReset(false); }, 3500);
    } catch(e) {
      setPwMsg("❌ Erreur : " + e.message);
    }
  };

  const thS = {padding:"7px 10px",fontSize:11,fontWeight:700,color:"#64748b",background:"#f8fafc",borderBottom:"2px solid #e2e8f0",textAlign:"center"};
  const tdS = {padding:"6px 8px",borderBottom:"1px solid #f1f5f9",textAlign:"center",fontSize:12};

  return(
    <div style={{padding:0}}>
      <ConfirmDelete open={!!deletingU} onClose={()=>setDeletingU(null)}
        label={deletingU?.name||""} onConfirm={async()=>{ await store.deleteUser(deletingU.id); setDeletingU(null); }}/>

      <PageHeader pageId="utilisateurs" title="👥 Utilisateurs" subtitle="Gestion des accès et rôles">
        <button onClick={openAdd} style={{...btn(),background:"white",color:"#4c0519",fontWeight:700}}>+ Nouveau</button>
      </PageHeader>

      <div style={{padding:16}}>
        {/* Modal ajout/modif utilisateur */}
        <Modal open={show} onClose={()=>setShow(false)} title={editing?"✏️ Modifier Utilisateur":"👤 Nouvel Utilisateur"}>
          <div style={{marginBottom:12}}><label style={label}>Nom complet</label><input style={input} value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))}/></div>
          <div style={{marginBottom:12}}><label style={label}>Email</label><input style={{...input,background:editing?"#f8fafc":"white"}} type="email" value={form.email} onChange={e=>setForm(f=>({...f,email:e.target.value}))} disabled={!!editing}/></div>
          <div style={{marginBottom:12}}>
            <label style={label}>Rôle</label>
            <select style={input} value={form.role} onChange={e=>setForm(f=>({...f,role:e.target.value}))}>
              {Object.entries(ROLES).map(([k,v])=><option key={k} value={k}>{v.label}</option>)}
            </select>
          </div>
          {!editing&&(
            <div style={{marginBottom:16}}>
              <label style={label}>Mot de passe provisoire <span style={{color:"#94a3b8",fontWeight:400}}>(optionnel)</span></label>
              <div style={{position:"relative"}}>
                <input
                  style={{...input,paddingRight:38}}
                  type={showTempPw?"text":"password"}
                  value={form.tempPw}
                  onChange={e=>setForm(f=>({...f,tempPw:e.target.value}))}
                  placeholder="Laissez vide pour utiliser PharmaStock2025!"/>
                <button onClick={()=>setShowTempPw(v=>!v)}
                  style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",color:"#64748b",fontSize:16,padding:0}}>
                  {showTempPw?"🙈":"👁️"}
                </button>
              </div>
              <div style={{background:"#f0f9ff",borderRadius:8,padding:10,fontSize:11,color:"#0891b2",marginTop:6}}>
                ℹ️ Mot de passe par défaut : <b>PharmaStock2025!</b> — L'utilisateur devra le changer à la première connexion.
              </div>
            </div>
          )}
          <button onClick={save} disabled={!form.name||!form.email}
            style={{...btn(),background:"#0891b2",color:"white",width:"100%",padding:11}}>
            {editing?"✏️ Enregistrer":"💾 Créer l'utilisateur"}
          </button>
        </Modal>

        {/* Modal permissions granulaires */}
        <Modal open={!!permTab} onClose={()=>setPermTab(null)} title={"🔐 Permissions — " + (permTab?.name||"")}>
          <div style={{fontSize:12,color:"#64748b",marginBottom:12}}>
            Rôle de base : <Badge color={ROLES[permTab?.role]?.color}>{ROLES[permTab?.role]?.label}</Badge>
            <br/><span style={{fontSize:11}}>Ces cases personnalisent les droits par rapport aux droits du rôle.</span>
          </div>
          <div style={{overflowX:"auto"}}>
            <table style={{width:"100%",borderCollapse:"collapse"}}>
              <thead>
                <tr>
                  <th style={{...thS,textAlign:"left"}}>Section</th>
                  <th style={thS}>👁️ Consulter</th>
                  <th style={thS}>✏️ Modifier</th>
                  <th style={thS}>🗑️ Supprimer</th>
                </tr>
              </thead>
              <tbody>
                {SECTIONS.map(s => (
                  <tr key={s.id}>
                    <td style={{...tdS,textAlign:"left",fontWeight:500,color:"#1e293b"}}>{s.label}</td>
                    {["r","w","d"].map(right=>(
                      <td key={right} style={tdS}>
                        <input type="checkbox"
                          checked={!!(permForm[s.id]?.[right])}
                          onChange={()=>togglePerm(s.id,right)}
                          style={{width:16,height:16,cursor:"pointer",accentColor:"#0891b2"}}/>
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <button onClick={savePerms} style={{...btn(),background:"#0891b2",color:"white",width:"100%",padding:11,marginTop:16}}>
            💾 Enregistrer les permissions
          </button>
        </Modal>

        {/* Modal réinitialisation mot de passe */}
        <Modal open={!!resetPwU} onClose={()=>{setResetPwU(null);setPwMsg("");setNewPw("");}} title={"🔑 Mot de passe — " + (resetPwU?.name||"")}>
          {pwMsg ? (
            <Alert type={pwMsg.startsWith("✅")?"success":pwMsg.startsWith("⚠️")?"warn":"error"}>{pwMsg}</Alert>
          ) : (
            <>
              <div style={{fontSize:13,color:"#64748b",marginBottom:12}}>
                Définir un mot de passe provisoire pour <b>{resetPwU?.name}</b> ({resetPwU?.email})
              </div>
              <div style={{marginBottom:12}}>
                <label style={label}>Nouveau mot de passe provisoire</label>
                <div style={{position:"relative"}}>
                  <input
                    style={{...input,paddingRight:38}}
                    type={showPwReset?"text":"password"}
                    value={newPw}
                    onChange={e=>setNewPw(e.target.value)}
                    placeholder="Minimum 6 caractères"/>
                  <button onClick={()=>setShowPwReset(v=>!v)}
                    style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",color:"#64748b",fontSize:16,padding:0}}>
                    {showPwReset?"🙈":"👁️"}
                  </button>
                </div>
              </div>
              <div style={{display:"flex",gap:8}}>
                <button onClick={handleResetPassword}
                  style={{...btn(),background:"#0891b2",color:"white",flex:1,padding:11,fontSize:13}}>
                  💾 Définir ce mot de passe
                </button>
                <button onClick={()=>{ store.updateUser(resetPwU.id,{mustChangePw:true}); sendPasswordResetEmail(auth,resetPwU.email).then(()=>setPwMsg("✅ Email envoyé à "+resetPwU.email)).catch(e=>setPwMsg("❌ "+e.message)); }}
                  style={{...btn(),background:"#f59e0b",color:"white",flex:1,padding:11,fontSize:13}}>
                  📧 Envoyer email reset
                </button>
              </div>
            </>
          )}
        </Modal>

        {/* Liste utilisateurs */}
        <div style={{display:"flex",flexDirection:"column",gap:8}}>
          {store.users.map(u=>{
            const isSuperuser    = u.isSuperuser || u.role==="superuser";
            const isTargetAdmin  = u.role==="admin";
            const isCurrentUser  = u.id===currentUser?.uid;
            const amISuperuser   = currentUser?.isSuperuser || currentUser?.role==="superuser";
            const amIAdmin       = currentUser?.role==="admin";

            // Règles de protection :
            // - Superuser → intouchable par tout le monde
            // - Admin cible → seul le superuser peut le modifier/supprimer/démettre
            // - Soi-même → ne peut pas se supprimer ni se démettre
            const isProtected    = isSuperuser || (isTargetAdmin && !amISuperuser);
            const canEdit        = !isSuperuser && (!isTargetAdmin || amISuperuser) && !isCurrentUser;
            const canEditPerms   = !isSuperuser && (!isTargetAdmin || amISuperuser);
            const canResetPw     = !isSuperuser && (!isTargetAdmin || amISuperuser);
            const canDelete      = !isSuperuser && !isCurrentUser && (!isTargetAdmin || amISuperuser);
            const canToggleAdmin = !isSuperuser && !isCurrentUser && amISuperuser; // seul superuser peut promouvoir/rétrograder admin

            return(
            <div key={u.id} style={{...card,padding:14,border:isSuperuser?"2px solid #f59e0b":isTargetAdmin?"2px solid #7c3aed":"1.5px solid #f1f5f9"}}>
              <div style={{display:"flex",alignItems:"center",gap:12}}>
                <div style={{width:40,height:40,borderRadius:"50%",background:(ROLES[u.role]?.color||"#94a3b8")+"22",display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,flexShrink:0}}>
                  {isSuperuser?"⭐":isTargetAdmin?"🛡️":"👤"}
                </div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{display:"flex",alignItems:"center",gap:6}}>
                    <div style={{fontWeight:700,color:"#1e293b",fontSize:13}}>{u.name}</div>
                    {isSuperuser&&<span style={{background:"#f59e0b",color:"white",fontSize:9,fontWeight:700,borderRadius:99,padding:"1px 6px"}}>SUPER</span>}
                    {isTargetAdmin&&!isSuperuser&&<span style={{background:"#7c3aed",color:"white",fontSize:9,fontWeight:700,borderRadius:99,padding:"1px 6px"}}>ADMIN</span>}
                  </div>
                  <div style={{fontSize:11,color:"#64748b"}}>{u.email}</div>
                  <Badge color={ROLES[u.role]?.color||"#94a3b8"}>{ROLES[u.role]?.label||u.role}</Badge>
                  {u.permissions&&<span style={{fontSize:10,color:"#7c3aed",marginLeft:6}}>🔐 Perms perso.</span>}
                  {u.mustChangePw&&<span style={{fontSize:10,color:"#f59e0b",marginLeft:6}}>⚠️ Doit changer mdp</span>}
                </div>
                <div style={{display:"flex",gap:5,flexWrap:"wrap",justifyContent:"flex-end"}}>
                  {canEdit      &&<button onClick={()=>openEdit(u)}    style={{...btn(),background:"#f0f9ff",color:"#0891b2",padding:"5px 8px",fontSize:11}} title="Modifier">✏️</button>}
                  {canEditPerms &&<button onClick={()=>openPerms(u)}   style={{...btn(),background:"#fdf4ff",color:"#7c3aed",padding:"5px 8px",fontSize:11}} title="Permissions">🔐</button>}
                  {canResetPw   &&<button onClick={()=>setResetPwU(u)} style={{...btn(),background:"#fffbeb",color:"#d97706",padding:"5px 8px",fontSize:11}} title="Mot de passe provisoire">🔑</button>}
                  {canToggleAdmin&&(
                    <button onClick={()=>store.updateUser(u.id,{role:u.role==="admin"?"magasinier":"admin"})}
                      style={{...btn(),background:u.role==="admin"?"#ede9fe":"#f8fafc",color:u.role==="admin"?"#7c3aed":"#64748b",padding:"5px 8px",fontSize:11}}
                      title={u.role==="admin"?"Retirer admin":"Promouvoir admin"}>
                      {u.role==="admin"?"🛡️ -Admin":"🛡️ Admin"}
                    </button>
                  )}
                  {canDelete    &&<button onClick={()=>setDeletingU(u)} style={{...btn(),background:"#fee2e2",color:"#ef4444",padding:"5px 8px",fontSize:11}} title="Supprimer">🗑️</button>}
                  {isProtected  &&!isCurrentUser&&<span style={{fontSize:10,color:isSuperuser?"#f59e0b":"#7c3aed",padding:"5px 4px"}}>🔒</span>}
                </div>
              </div>
            </div>
            );
          })}
          {store.users.length===0&&<div style={{...card,textAlign:"center",padding:40,color:"#94a3b8"}}>Aucun utilisateur.</div>}
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// LOGIN — Firebase Auth
// ─────────────────────────────────────────────
function LoginPage({onLogin}){
  const [email,   setEmail]   = useState("");
  const [password,setPassword]= useState("");
  const [err,     setErr]     = useState("");
  const [loading, setLoading] = useState(false);
  const [showPw,  setShowPw]  = useState(false);

  const tryLogin = async () => {
    if (!email || !password) { setErr("Veuillez saisir votre email et mot de passe."); return; }
    setLoading(true); setErr("");
    try {
      const cred = await signInWithEmailAndPassword(auth, email, password);
      // Charger le profil Firestore
      const snap = await getDoc(doc(db, "users", cred.user.uid));
      let profile;
      if (snap.exists()) {
        profile = { uid: cred.user.uid, ...snap.data() };
      } else {
        // Premier utilisateur : créer profil admin automatiquement
        profile = {
          uid:   cred.user.uid,
          name:  cred.user.displayName || email.split("@")[0],
          email: cred.user.email,
          role:  "admin",
        };
        await setDoc(doc(db, "users", cred.user.uid), {
          ...profile, createdAt: serverTimestamp(),
        });
      }
      onLogin(profile);
    } catch(e) {
      const msgs = {
        "auth/wrong-password":    "Mot de passe incorrect.",
        "auth/user-not-found":    "Aucun compte avec cet email.",
        "auth/invalid-email":     "Format d'email invalide.",
        "auth/invalid-credential":"Email ou mot de passe incorrect.",
        "auth/too-many-requests": "Trop de tentatives. Réessayez plus tard.",
      };
      setErr(msgs[e.code] || "Erreur : " + e.message);
    } finally { setLoading(false); }
  };

  return(
    <div style={{minHeight:"100vh",background:"linear-gradient(135deg,#0f172a,#1e3a5f)",display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{background:"white",borderRadius:20,padding:32,width:"100%",maxWidth:400,boxShadow:"0 20px 60px rgba(0,0,0,0.3)"}}>
        <div style={{textAlign:"center",marginBottom:28}}>
          <img src={LOGO_B64} alt="CHNCAK" style={{width:100,height:100,borderRadius:"50%",objectFit:"cover",marginBottom:12,border:"3px solid #0891b2",boxShadow:"0 4px 20px rgba(8,145,178,0.3)"}}/>
          <div style={{fontSize:11,fontWeight:700,color:"#64748b",letterSpacing:1,textTransform:"uppercase"}}>Centre Hospitalier National Cheikh Ahmadoul Khadim</div>
          <div style={{fontSize:20,fontWeight:800,color:"#0f172a",marginTop:4}}>PharmaStock</div>
          <div style={{fontSize:12,color:"#64748b",marginTop:2}}>Gestion des Inventaires Pharmaceutiques</div>
        </div>
        {err&&<Alert type="error">❌ {err}</Alert>}
        <div style={{marginBottom:14}}>
          <label style={label}>Email</label>
          <input style={input} type="email" value={email}
            onChange={e=>setEmail(e.target.value)}
            placeholder="votre@email.com"
            onKeyDown={e=>e.key==="Enter"&&tryLogin()}/>
        </div>
        <div style={{marginBottom:20}}>
          <label style={label}>Mot de passe</label>
          <div style={{position:"relative"}}>
            <input style={{...input,paddingRight:38}} type={showPw?"text":"password"} value={password}
              onChange={e=>setPassword(e.target.value)}
              placeholder="••••••••"
              onKeyDown={e=>e.key==="Enter"&&tryLogin()}/>
            <button onClick={()=>setShowPw(v=>!v)}
              style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",color:"#64748b",fontSize:16,padding:0,lineHeight:1}}>
              {showPw?"🙈":"👁️"}
            </button>
          </div>
        </div>
        <button onClick={tryLogin} disabled={loading}
          style={{...btn(),width:"100%",padding:13,background:loading?"#cbd5e1":"linear-gradient(135deg,#0891b2,#0e7490)",color:"white",fontSize:15}}>
          {loading?"⏳ Connexion en cours...":"Se Connecter"}
        </button>
        <div style={{marginTop:16,fontSize:11,color:"#94a3b8",textAlign:"center"}}>
          🔒 Authentification sécurisée Firebase
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// MAIN APP — avec Firebase Auth persistante
// ─────────────────────────────────────────────
export default function App(){
  const [user,            setUser]            = useState(null);
  const [authLoading,     setAuthLoading]     = useState(true);
  const [page,            setPage]            = useState("dashboard");
  const [menuOpen,        setMenuOpen]        = useState(false);
  const [aiOpen,          setAiOpen]          = useState(false);
  const [supplierModal,   setSupplierModal]   = useState(false);
  const [activeSupplier,  setActiveSupplierState] = useState(null);
  const [pendingInvoiceId,setPendingInvoiceId] = useState(null);
  const [profileOpen,setProfileOpen] = useState(false);
  const [profilePw,setProfilePw]     = useState({current:"",next:"",confirm:""});
  const [profileMsg,setProfileMsg]   = useState("");

  const handleUpdatePassword = async () => {
    if(profilePw.next.length<6){setProfileMsg("❌ Minimum 6 caractères.");return;}
    if(profilePw.next!==profilePw.confirm){setProfileMsg("❌ Les mots de passe ne correspondent pas.");return;}
    try{
      await updatePassword(auth.currentUser, profilePw.next);
      setProfileMsg("✅ Mot de passe modifié avec succès !");
      setProfilePw({current:"",next:"",confirm:""});
      setTimeout(()=>{setProfileOpen(false);setProfileMsg("");},2000);
    }catch(e){
      if(e.code==="auth/requires-recent-login") setProfileMsg("❌ Session expirée. Reconnectez-vous.");
      else setProfileMsg("❌ Erreur : "+e.message);
    }
  }; // facture à pré-remplir en messagerie

  // ── Firebase Auth : détecte session existante au chargement ──
  useEffect(()=>{
    const unsub = onAuthStateChanged(auth, async fbUser => {
      if (fbUser) {
        try {
          const snap = await getDoc(doc(db,"users",fbUser.uid));
          if (snap.exists()) {
            setUser({ uid: fbUser.uid, ...snap.data() });
          } else {
            // Profil manquant → créer automatiquement en admin
            const profile = {
              name:  fbUser.displayName || fbUser.email.split("@")[0],
              email: fbUser.email,
              role:  "admin",
            };
            await setDoc(doc(db,"users",fbUser.uid), { ...profile, createdAt: serverTimestamp() });
            setUser({ uid: fbUser.uid, ...profile });
          }
        } catch(e) {
          console.error("Erreur chargement profil:", e);
          setUser(null);
        }
      } else {
        setUser(null);
      }
      setAuthLoading(false);
    });
    return unsub;
  },[]);

  const store = useStore(user?.uid, user?.name || user?.email || "Inconnu");
  const ai    = useAI();

  // ── Restaurer fournisseur actif depuis Firestore user doc ──
  useEffect(()=>{
    if(user?.activeSupplier && store.suppliers.length > 0){
      const found = store.suppliers.find(s=>s.id===user.activeSupplier);
      if(found) setActiveSupplierState(found);
    }
  },[user?.uid, store.suppliers.length]);

  const setActiveSupplier = async (s) => {
    setActiveSupplierState(s);
    setSupplierModal(false); setMenuOpen(false);
    // Persister dans le profil Firestore de l'utilisateur
    if(user?.uid) {
      try {
        await updateDoc(doc(db,"users",user.uid), { activeSupplier: s?.id || null });
      } catch(e) { console.warn("Erreur sauvegarde fournisseur:", e); }
    }
  };

  const nav = (p, extra={}) => {
    setPage(p);
    setMenuOpen(false);
    setAiOpen(false);
    if(extra.invoiceId !== undefined) setPendingInvoiceId(extra.invoiceId);
  };
  const logout = async () => {
    await signOut(auth);
    setUser(null);
    setActiveSupplierState(null);
    setPage("dashboard");
  };

  // ── Écran de chargement pendant vérification Auth ──
  if(authLoading) return (
    <div style={{minHeight:"100vh",background:"linear-gradient(135deg,#0f172a,#1e3a5f)",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:20}}>
      <img src={LOGO_B64} alt="CHNCAK" style={{width:90,height:90,borderRadius:"50%",objectFit:"cover",border:"3px solid #38bdf8"}}/>
      <div style={{color:"#38bdf8",fontWeight:700,fontSize:16}}>CHNCAK PharmaStock</div>
      <div style={{color:"#64748b",fontSize:13}}>⏳ Chargement en cours...</div>
    </div>
  );

  if(!user) return <LoginPage onLogin={setUser}/>;

  // ── Écran de chargement des données Firestore ──
  if(store.loading) return (
    <div style={{minHeight:"100vh",background:"#f8fafc",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:16}}>
      <img src={LOGO_B64} alt="CHNCAK" style={{width:70,height:70,borderRadius:"50%",objectFit:"cover",border:"3px solid #0891b2"}}/>
      <div style={{color:"#0891b2",fontWeight:700}}>Synchronisation des données...</div>
      <div style={{color:"#94a3b8",fontSize:12}}>Connexion à Firebase en cours</div>
    </div>
  );

  const unread=store.messages.filter(m=>!m.read).length;
  const role=user.role||"magasinier";
  const activeDepot=activeSupplier ? store.depots.find(d=>d.supplierId===activeSupplier.id) : null;

  const renderPage=()=>{
    const props={store,activeSupplier,activeDepot,onNav:nav,currentUser:user};
    switch(page){
      case "dashboard":    return <Dashboard {...props}/>;
      case "entrees":      return <DocumentForm type="entry"  {...props} ai={ai}/>;
      case "retours":      return <DocumentForm type="return" {...props} ai={ai}/>;
      case "inventaire":   return <InventoryPage store={store} activeSupplier={activeSupplier} currentUser={user}/>;
      case "factures":     return <InvoicesPage store={store} activeSupplier={activeSupplier} onNav={nav} currentUser={user}/>;
      case "hist-inv":
        return <InventoryHistoryPage store={store} activeSupplier={activeSupplier} user={user}/>;
      case "hist-fact": {
        const factItems=store.invoices.filter(i=>!activeSupplier||i.supplierId===activeSupplier?.id);
        const exportFactCSV=()=>{
          const rows=factItems.flatMap(inv=>(inv.items||[]).map(it=>[inv.reference,inv.month,inv.supplier,it.productName,it.qty,Number(it.unitPrice||0),Number(it.total||0),Number(inv.total||0)]));
          downloadExcel("historique_factures_"+Date.now()+".xlsx",rows,["Référence","Période","Fournisseur","Produit","Qté","Prix unit. FCFA","Total ligne FCFA","Total facture FCFA"]);
        };
        return <HistoryPage title="Historique Factures" icon="📁" pageId="hist-fact" items={factItems} empty="Aucune facture." onExportCSV={exportFactCSV}
          renderItem={inv=>(
            <div key={inv.id} style={{...card,display:"flex",justifyContent:"space-between",flexWrap:"wrap",gap:8,alignItems:"center"}}>
              <div>
                <div style={{fontWeight:700,color:"#1e293b",fontSize:13}}>{inv.reference}</div>
                <div style={{fontSize:11,color:"#64748b"}}>{inv.supplier} · {inv.month}</div>
                {inv.createdByName&&<div style={{fontSize:10,color:"#94a3b8"}}>👤 {inv.createdByName}</div>}
              </div>
              <div style={{display:"flex",alignItems:"center",gap:6,flexWrap:"wrap"}}>
                <div style={{fontWeight:800,color:"#0891b2",fontSize:14}}>{Number(inv.total||0).toLocaleString("fr-FR")} FCFA</div>
                {/* CSV */}
                <button onClick={e=>{e.stopPropagation();downloadInvoiceCSV(inv);}} style={{background:"#f0fdf4",color:"#059669",border:"1px solid #bbf7d0",borderRadius:6,padding:"3px 8px",cursor:"pointer",fontSize:11,fontWeight:600}}>⬇️ CSV</button>
                {/* PDF */}
                <button onClick={e=>{
                  e.stopPropagation();
                  const tbl=""+pdfHeader("FACTURE",inv.reference)+
                    "<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:14px;\">"+
                    "<div style=\"background:#f8fafc;padding:8px 10px;border-radius:6px;\"><div style=\"font-size:9px;font-weight:700;color:#64748b;text-transform:uppercase;\">Fournisseur</div><div style=\"font-weight:600;\">"+inv.supplier+"</div></div>"+
                    "<div style=\"background:#f8fafc;padding:8px 10px;border-radius:6px;\"><div style=\"font-size:9px;font-weight:700;color:#64748b;text-transform:uppercase;\">Période</div><div style=\"font-weight:600;\">"+inv.month+"</div></div></div>"+
                    "<table><tr><th>Produit</th><th>Qté</th><th>Prix unit.</th><th>Total</th></tr>"+
                    (inv.items||[]).map(it=>"<tr><td>"+it.productName+"</td><td>"+it.qty+"</td><td>"+Number(it.unitPrice||0).toLocaleString("fr-FR")+" FCFA</td><td>"+Number(it.total||0).toLocaleString("fr-FR")+" FCFA</td></tr>").join("")+
                    "<tr class=\"total-row\"><td colspan=3>TOTAL</td><td>"+Number(inv.total||0).toLocaleString("fr-FR")+" FCFA</td></tr></table>"+
                    "<div class=\"footer\">Généré le "+new Date().toLocaleDateString("fr-FR")+"</div>";
                  downloadPDF("facture_"+inv.reference,tbl);
                }} style={{background:"#fef3c7",color:"#92400e",border:"1px solid #fcd34d",borderRadius:6,padding:"3px 8px",cursor:"pointer",fontSize:11,fontWeight:600}}>⬇️ PDF</button>
                {/* Mail */}
                <button onClick={e=>{
                  e.stopPropagation();
                  const details=(inv.items||[]).map(it=>`- ${it.productName} | Qté: ${it.qty} | Total: ${Number(it.total||0).toLocaleString("fr-FR")} FCFA`).join("\n");
                  openMailClient({
                    to: activeSupplier?.email || "",
                    subject: `Facture ${inv.reference} — ${inv.month}`,
                    body:
                      `Bonjour,\n\n`+
                      `Veuillez trouver ci-joint la facture ${inv.reference} pour la période ${inv.month}.\n\n`+
                      `Fournisseur : ${inv.supplier}\n`+
                      `Période     : ${inv.month}\n\n`+
                      `Détails :\n${details}\n\n`+
                      `TOTAL : ${Number(inv.total||0).toLocaleString("fr-FR")} FCFA\n\n`+
                      `Cordialement,\nCHNCAK PharmaStock`
                  });
                }} style={{background:"#0891b2",color:"white",border:"none",borderRadius:6,padding:"3px 8px",cursor:"pointer",fontSize:11,fontWeight:600}}>📧 Mail</button>
                {can(user,"hist-fact","d")&&<button onClick={e=>{e.stopPropagation();store.deleteInvoice(inv.id);}} style={{background:"#fee2e2",color:"#ef4444",border:"none",borderRadius:6,padding:"3px 8px",cursor:"pointer",fontSize:11,fontWeight:600}}>🗑️</button>}
              </div>
            </div>
          )}/>;
      }
      case "messagerie":   return <MessagingPage store={store} activeSupplier={activeSupplier} pendingInvoiceId={pendingInvoiceId} onClearPending={()=>setPendingInvoiceId(null)} currentUser={user}/>;
      case "produits":     return <ProductsPage store={store} activeSupplier={activeSupplier} currentUser={user}/>;
      case "depots":       return <DepotsPage store={store} activeSupplier={activeSupplier} currentUser={user}/>;
      case "fournisseurs": return <FournisseursPage store={store} activeSupplier={activeSupplier} onActivate={setActiveSupplier} currentUser={user}/>;
      case "utilisateurs": return role==="admin"?<UsersPage store={store} currentUser={user}/>:<div style={{padding:24}}><Alert type="error">Accès refusé.</Alert></div>;
      default:             return <Dashboard store={store} activeSupplier={activeSupplier} activeDepot={activeDepot}/>;
    }
  };

  return(
    <div style={{display:"flex",flexDirection:"column",height:"100vh",background:"#f8fafc",fontFamily:"-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif",overflow:"hidden"}}>
      <TopBar page={page} activeSupplier={activeSupplier} onMenu={()=>setMenuOpen(true)}
        onAI={()=>{setAiOpen(v=>!v);setMenuOpen(false);}} aiOpen={aiOpen}
        unread={unread} onLogout={logout} onChangeSupplier={()=>setSupplierModal(true)} onNav={nav}
        onProfile={()=>setProfileOpen(true)} userName={user?.name||user?.email}/>
      <div style={{flex:1,overflowY:"auto"}}>
        {renderPage()}
      </div>
      <Sidebar open={menuOpen} onClose={()=>setMenuOpen(false)} page={page} onNav={nav}
        user={user} unread={unread} activeSupplier={activeSupplier}
        onChangeSupplier={()=>{setSupplierModal(true);setMenuOpen(false);}}/>
      <AIPanel open={aiOpen} onClose={()=>setAiOpen(false)} ai={ai} onNav={nav}
        store={store} page={page} activeSupplier={activeSupplier} currentUser={user}/>
      {/* Modal Mon Profil */}
      <Modal open={profileOpen} onClose={()=>{setProfileOpen(false);setProfileMsg("");setProfilePw({current:"",next:"",confirm:""});}} title="👤 Mon Profil">
        <div style={{marginBottom:16}}>
          <div style={{display:"flex",alignItems:"center",gap:12,padding:"12px 0",borderBottom:"1px solid #f1f5f9",marginBottom:14}}>
            <div style={{width:50,height:50,borderRadius:"50%",background:ROLES[user?.role]?.color+"22",display:"flex",alignItems:"center",justifyContent:"center",fontSize:24}}>👤</div>
            <div>
              <div style={{fontWeight:700,color:"#1e293b",fontSize:15}}>{user?.name}</div>
              <div style={{fontSize:12,color:"#64748b"}}>{user?.email}</div>
              <Badge color={ROLES[user?.role]?.color}>{ROLES[user?.role]?.label}</Badge>
            </div>
          </div>
          <div style={{fontWeight:700,color:"#374151",fontSize:13,marginBottom:12}}>🔑 Changer mon mot de passe</div>
          {profileMsg&&<Alert type={profileMsg.startsWith("✅")?"success":"error"}>{profileMsg}</Alert>}
          <div style={{marginBottom:10}}><label style={label}>Nouveau mot de passe</label>
            <input style={input} type="password" value={profilePw.next}
              onChange={e=>setProfilePw(p=>({...p,next:e.target.value}))} placeholder="Minimum 6 caractères"/>
          </div>
          <div style={{marginBottom:16}}><label style={label}>Confirmer</label>
            <input style={input} type="password" value={profilePw.confirm}
              onChange={e=>setProfilePw(p=>({...p,confirm:e.target.value}))} placeholder="Répéter le mot de passe"/>
          </div>
          <button onClick={handleUpdatePassword}
            disabled={!profilePw.next||!profilePw.confirm}
            style={{...btn(),background:"#0891b2",color:"white",width:"100%",padding:11,fontSize:14}}>
            🔑 Mettre à jour le mot de passe
          </button>
        </div>
      </Modal>

      <SupplierSelector open={supplierModal} suppliers={store.suppliers} current={activeSupplier}
        onSelect={setActiveSupplier} onClose={()=>setSupplierModal(false)}/>
    </div>
  );
}